  const handleViewChange = (newView: ViewState) => {
    setView(newView);
    setSelectedTeacher(null);
    setSelectedGroup(null);
  };

  const renderContent = () => {
    switch (view) {
      case 'students':
        return <StudentList students={students} onDelete={(id) => setStudents(s => s.filter(st => st.id !== id))} />;
      case 'teachers':
        if (selectedTeacher) {
          return (
            <TeacherDetails 
              teacher={selectedTeacher} 
              groups={groups} 
              events={events}
              students={students}
              onBack={handleBackToTeacherList} 
            />
          );
        }
        return (
          <TeacherList 
            teachers={teachers} 
            onDelete={(id) => setTeachers(t => t.filter(tch => tch.id !== id))} 
            onSelect={handleTeacherSelect}
          />
        );
      case 'groups':
        if (selectedGroup) {
          return (
            <GroupDetails
              group={selectedGroup}
              students={students}
              teachers={teachers}
              events={events}
              onBack={() => setSelectedGroup(null)}
              onUpdateGroup={handleUpdateGroup}
            />
          );
        }
        return (
          <GroupManager 
            students={students} 
            groups={groups} 
            setGroups={setGroups} 
            onSelect={handleGroupSelect}
          />
        );
      case 'scheduler':
        return <Scheduler groups={groups} events={events} setEvents={setEvents} />;
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-gray-800">Dashboard Overview</h2>

