import React, { useState } from 'react';
import { Group, Student, Teacher, CalendarEvent } from '../types';
import { ArrowLeft, Users, Calendar, BookOpen, User, Clock, CheckCircle2, Plus, X } from 'lucide-react';

interface GroupDetailsProps {
  group: Group;
  students: Student[];
  teachers: Teacher[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'student' | 'scheduler';

export const GroupDetails: React.FC<GroupDetailsProps> = ({ group, students, teachers, events, onBack, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isAddingStudent, setIsAddingStudent] = useState(false);
  const [selectedStudentId, setSelectedStudentId] = useState('');

  // Derived data
  const groupStudents = students.filter(s => group.studentIds.includes(s.id));
  const groupTeacher = teachers.find(t => t.id === group.teacherId);
  const groupEvents = events
    .filter(e => e.groupId === group.id)
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  // Available students to add (not currently in group)
  const availableStudents = students.filter(s => !group.studentIds.includes(s.id));

  const handleAddStudent = () => {
    if (selectedStudentId) {
      const updatedGroup = {
        ...group,
        studentIds: [...group.studentIds, selectedStudentId]
      };
      onUpdateGroup(updatedGroup);
      setSelectedStudentId('');
      setIsAddingStudent(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
          onClick={onBack} 
          className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
        >
          <ArrowLeft size={18} />
          Back to Groups
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
          <div className="w-20 h-20 bg-indigo-100 rounded-xl flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             <Users size={40} />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-800">{group.name}</h1>
            <p className="text-lg text-gray-600 mt-1">{group.description}</p>
            <div className="flex items-center gap-4 mt-3 text-sm text-gray-500">
              <span className="flex items-center gap-1"><Users size={16} /> {groupStudents.length} Students</span>
              {groupTeacher && (
                <span className="flex items-center gap-1 bg-purple-50 text-purple-700 px-2 py-0.5 rounded-full border border-purple-100">
                  <User size={14} /> Teacher: {groupTeacher.name}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="flex border-b border-gray-200">
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Details
          </button>
          <button 
            onClick={() => setActiveTab('student')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'student' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Student
          </button>
          <button 
            onClick={() => setActiveTab('scheduler')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'scheduler' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Scheduler
          </button>
        </div>

        <div className="p-6 min-h-[300px]">
          {/* Details Tab */}
          {activeTab === 'details' && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="p-5 bg-gray-50 rounded-xl border border-gray-100">
                  <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                    <BookOpen size={20} className="text-indigo-500"/> Group Information
                  </h3>
                  <div className="space-y-3">
                    <div className="flex justify-between py-2 border-b border-gray-200">
                      <span className="text-gray-600">Total Students</span>
                      <span className="font-semibold">{groupStudents.length}</span>
                    </div>
                    <div className="flex justify-between py-2 border-b border-gray-200">
                      <span className="text-gray-600">Scheduled Sessions</span>
                      <span className="font-semibold">{groupEvents.length}</span>
                    </div>
                    {groupTeacher ? (
                      <div className="flex justify-between py-2 border-b border-gray-200">
                        <span className="text-gray-600">Assigned Teacher</span>
                        <span className="font-semibold text-indigo-600">{groupTeacher.name}</span>
                      </div>
                    ) : (
                      <div className="py-2 text-yellow-600 italic text-sm">
                        No teacher assigned yet.
                      </div>
                    )}
                  </div>
                </div>

                <div className="p-5 bg-indigo-50 rounded-xl border border-indigo-100">
                  <h3 className="font-bold text-indigo-900 mb-4 flex items-center gap-2">
                    <CheckCircle2 size={20} className="text-indigo-600"/> Quick Status
                  </h3>
                  <p className="text-indigo-800 text-sm mb-4">
                    This group is currently active. Students are assigned based on the selected criteria.
                  </p>
                  <div className="flex gap-2">
                    {groupStudents.length > 0 ? (
                      <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold border border-green-200">Active</span>
                    ) : (
                      <span className="bg-yellow-100 text-yellow-700 px-3 py-1 rounded-full text-xs font-bold border border-yellow-200">Empty</span>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Student Tab */}
          {activeTab === 'student' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-800">Students in {group.name}</h3>
                <button 
                  onClick={() => setIsAddingStudent(!isAddingStudent)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition ${isAddingStudent ? 'bg-gray-100 text-gray-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
                >
                  {isAddingStudent ? <X size={16} /> : <Plus size={16} />}
                  {isAddingStudent ? 'Cancel' : 'Add Student'}
                </button>
              </div>

              {isAddingStudent && (
                <div className="bg-gray-50 p-4 rounded-xl border border-indigo-100 mb-6 animate-[fadeIn_0.2s_ease-out]">
                  <h4 className="font-semibold text-gray-700 mb-3 text-sm">Select a student to add:</h4>
                  {availableStudents.length === 0 ? (
                    <div className="text-gray-500 italic text-sm">All available students are already in this group.</div>
                  ) : (
                    <div className="flex flex-col sm:flex-row gap-3">
                      <select
                        value={selectedStudentId}
                        onChange={(e) => setSelectedStudentId(e.target.value)}
                        className="flex-1 p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-sm"
                      >
                        <option value="">-- Select Student --</option>
                        {availableStudents.map(student => (
                          <option key={student.id} value={student.id}>
                            {student.name} (Grade: {student.grade}%)
                          </option>
                        ))}
                      </select>
                      <button
                        onClick={handleAddStudent}
                        disabled={!selectedStudentId}
                        className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
                      >
                        Add to Group
                      </button>
                    </div>
                  )}
                </div>
              )}

              {groupStudents.length === 0 ? (
                <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                  <Users size={32} className="mx-auto mb-2 opacity-30" />
                  <p>No students assigned to this group.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {groupStudents.map(student => (
                    <div key={student.id} className="p-4 border border-gray-200 rounded-lg hover:border-indigo-300 transition bg-white flex items-center gap-3 shadow-sm">
                       <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold">
                          {student.name.charAt(0)}
                       </div>
                       <div>
                         <p className="font-semibold text-gray-800">{student.name}</p>
                         <p className="text-xs text-gray-500">Grade: {student.grade}%</p>
                       </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Scheduler Tab */}
          {activeTab === 'scheduler' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-800">Group Schedule</h3>
              </div>

              {groupEvents.length === 0 ? (
                 <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                   <Calendar size={32} className="mx-auto mb-2 opacity-30" />
                   <p>No sessions scheduled for this group.</p>
                 </div>
               ) : (
                 <div className="space-y-3">
                   {groupEvents.map(event => {
                     const date = new Date(event.startTime);
                     return (
                      <div key={event.id} className="flex items-start gap-4 p-4 border border-gray-100 rounded-lg bg-gray-50 hover:bg-white hover:shadow-sm transition">
                        <div className="flex-shrink-0 w-16 text-center bg-white rounded border border-gray-200 p-2">
                           <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('en-US', { weekday: 'short' })}</span>
                           <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                        </div>
                        <div>
                          <h4 className="font-bold text-gray-800">{event.title}</h4>
                          <p className="text-sm text-gray-600 flex items-center gap-2 mt-1">
                            <Clock size={14} /> 
                            {date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} - 
                            {new Date(date.getTime() + event.durationMinutes * 60000).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}
                          </p>
                          <p className="text-xs text-gray-500 mt-2">{event.description || 'No description provided.'}</p>
                        </div>
                        <div className="ml-auto">
                           <span className={`text-xs px-2 py-1 rounded font-medium uppercase ${event.type === 'class' ? 'bg-blue-100 text-blue-700' : event.type === 'meeting' ? 'bg-purple-100 text-purple-700' : 'bg-green-100 text-green-700'}`}>
                             {event.type}
                           </span>
                        </div>
                      </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Users, Calendar, Settings, BookOpen, GraduationCap, School } from 'lucide-react';
import { MOCK_STUDENTS, MOCK_GROUPS, MOCK_EVENTS, MOCK_TEACHERS } from './constants';
import { Student, Group, CalendarEvent, Teacher, ViewState } from './types';
import { StudentList } from './components/StudentList';
import { TeacherList } from './components/TeacherList';
import { TeacherDetails } from './components/TeacherDetails';
import { GroupManager } from './components/GroupManager';
import { GroupDetails } from './components/GroupDetails';
import { Scheduler } from './components/Scheduler';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);

  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(MOCK_TEACHERS);
  const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
  const [events, setEvents] = useState<CalendarEvent[]>(MOCK_EVENTS);

  // Computed Data
  const selectedTeacher = selectedTeacherId ? teachers.find(t => t.id === selectedTeacherId) || null : null;
  const selectedGroup = selectedGroupId ? groups.find(g => g.id === selectedGroupId) || null : null;

  // Computed Dashboard Stats
  const avgGrade = Math.round(students.reduce((acc, curr) => acc + curr.grade, 0) / students.length);
  const lowPerformance = students.filter(s => s.grade < 70).length;
  const upcomingEventsCount = events.length;

  const handleTeacherSelect = (teacher: Teacher) => {
    setSelectedTeacherId(teacher.id);
  };

  const handleBackToTeacherList = () => {
    setSelectedTeacherId(null);
  };

  const handleGroupSelect = (group: Group) => {
    setSelectedGroupId(group.id);
  }

  const handleUpdateGroup = (updatedGroup: Group) => {
    setGroups(prev => prev.map(g => g.id === updatedGroup.id ? updatedGroup : g));
  };

  // Reset selected items when changing main views
  const handleViewChange = (newView: ViewState) => {
    setView(newView);
    setSelectedTeacherId(null);
    setSelectedGroupId(null);
  };

  const renderContent = () => {
    switch (view) {
      case 'students':
        return <StudentList students={students} onDelete={(id) => setStudents(s => s.filter(st => st.id !== id))} />;
      case 'teachers':
        if (selectedTeacher) {
          return (
            <TeacherDetails 
              teacher={selectedTeacher} 
              groups={groups} 
              events={events}
              students={students}
              onBack={handleBackToTeacherList} 
            />
          );
        }
        return (
          <TeacherList 
            teachers={teachers} 
            onDelete={(id) => setTeachers(t => t.filter(tch => tch.id !== id))} 
            onSelect={handleTeacherSelect}
          />
        );
      case 'groups':
        if (selectedGroup) {
          return (
            <GroupDetails
              group={selectedGroup}
              students={students}
              teachers={teachers}
              events={events}
              onBack={() => setSelectedGroupId(null)}
              onUpdateGroup={handleUpdateGroup}
            />
          );
        }
        return (
          <GroupManager 
            students={students} 
            groups={groups} 
            setGroups={setGroups} 
            onSelect={handleGroupSelect}
          />
        );
      case 'scheduler':
        return <Scheduler groups={groups} events={events} setEvents={setEvents} />;
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-gray-800">Dashboard Overview</h2>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-blue-100 text-blue-600 rounded-lg">
                    <GraduationCap size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Total Students</p>
                    <p className="text-2xl font-bold text-gray-800">{students.length}</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-green-100 text-green-600 rounded-lg">
                    <BookOpen size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Class Average</p>
                    <p className="text-2xl font-bold text-gray-800">{avgGrade}%</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-purple-100 text-purple-600 rounded-lg">
                    <Calendar size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Upcoming Events</p>
                    <p className="text-2xl font-bold text-gray-800">{upcomingEventsCount}</p>
                  </div>
                </div>
              </div>
            </div>

