                  </div>

                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Note</label>
                      <textarea
                        value={newStudent.notes}
                        onChange={e => setNewStudent({...newStudent, notes: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="Any additional information..."
                        rows={2}
                      />
                  </div>
                </div>
              </div>

              {/* Parent Section */}
              <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100">
                <h4 className="font-semibold text-indigo-900 mb-3 flex items-center gap-2">
                  <UserCheck size={16} className="text-indigo-600"/> Parent / Guardian Information
                </h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Parent Name</label>
                    <input
                      type="text"
                      value={newStudent.parentName}
                      onChange={e => setNewStudent({...newStudent, parentName: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="e.g. Jane Doe"
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Email</label>
                      <input
                        type="email"
                        value={newStudent.parentEmail}
                        onChange={e => setNewStudent({...newStudent, parentEmail: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Phone</label>
                      <input
                        type="tel"
                        value={newStudent.parentPhone}
                        onChange={e => setNewStudent({...newStudent, parentPhone: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-100">
                <button
                  type="button"
                  onClick={() => setIsAdding(false)}
                  className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm"
                >
                  Save Student
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

{
  "name": "EduTrack",
  "description": "A comprehensive student tracking application for teachers featuring student management, group creation, and scheduling.",
  "requestFramePermissions": []
}

export interface Student {
  id: string;
  name: string;
  grade: number; // 0-100
  behaviorScore: number; // 0-10
  interests: string[];
  notes?: string;
  birthDate?: string;
  age?: number;
  email?: string;
  phone?: string;
  parentName?: string;
  parentPhone?: string;
  parentEmail?: string;
}

export interface Teacher {
  id: string;
  name: string;
  subject: string;
  email: string;
  yearsExperience: number;
}

export interface Group {
  id: string;
  name: string;
  description: string;
  studentIds: string[];
  teacherId?: string; // Link to a teacher
}

export interface CalendarEvent {
  id: string;
  title: string;
  description?: string;
  startTime: string; // ISO string
  durationMinutes: number;
  groupId?: string; // Optional linkage to a group
  teacherId?: string; // Optional linkage to a teacher
  type: 'class' | 'meeting' | 'activity';
}

export type ViewState = 'dashboard' | 'students' | 'teachers' | 'groups' | 'scheduler';

import React, { useState } from 'react';
import { Student, Group } from '../types';
import { Users, X, ChevronRight, Plus } from 'lucide-react';

interface GroupManagerProps {
  students: Student[];
  groups: Group[];
  setGroups: React.Dispatch<React.SetStateAction<Group[]>>;
  onSelect: (group: Group) => void;
}

export const GroupManager: React.FC<GroupManagerProps> = ({ students, groups, setGroups, onSelect }) => {
  const [newGroupName, setNewGroupName] = useState('');
  const [newGroupDesc, setNewGroupDesc] = useState('');

  const handleCreateGroup = () => {
    if (!newGroupName.trim()) return;
    const newGroup: Group = {
      id: crypto.randomUUID(),
      name: newGroupName,
      description: newGroupDesc || 'No description',
      studentIds: []
    };
    setGroups(prev => [...prev, newGroup]);
    setNewGroupName('');
    setNewGroupDesc('');
  };

  const deleteGroup = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this group?")) {
      setGroups(prev => prev.filter(g => g.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800">Group Management</h2>
      </div>

      {/* Manual Creation Panel */}
      <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
        <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Plus size={20} className="text-indigo-600"/>
          Create New Group
        </h3>
        <div className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            value={newGroupName}
            onChange={(e) => setNewGroupName(e.target.value)}
            placeholder="Group Name (e.g. Math Club)"
            className="flex-1 border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <input
            type="text"
            value={newGroupDesc}
            onChange={(e) => setNewGroupDesc(e.target.value)}
            placeholder="Description (Optional)"
            className="flex-[2] border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button
            onClick={handleCreateGroup}
            disabled={!newGroupName}
            className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition flex items-center gap-2 justify-center"
          >
            Create
          </button>
        </div>
      </div>

      {/* Group Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {groups.map((group) => (
          <div 
            key={group.id} 
            onClick={() => onSelect(group)}
            className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden cursor-pointer hover:shadow-md transition group"
          >
            <div className="p-4 border-b border-gray-100 bg-gray-50 flex justify-between items-start">
              <div>
                <h3 className="font-bold text-gray-800 flex items-center gap-2 group-hover:text-indigo-600 transition-colors">
                  <Users size={18} className="text-indigo-500" />
                  {group.name}
                </h3>
                <p className="text-xs text-gray-500 mt-1">{group.description}</p>
              </div>
              <div className="flex items-center gap-2">
                <button 
                  onClick={(e) => deleteGroup(e, group.id)} 
                  className="text-gray-400 hover:text-red-500 p-1 hover:bg-red-50 rounded"
                >
                  <X size={18} />
                </button>
                <ChevronRight size={18} className="text-gray-300" />
              </div>
            </div>
            <div className="p-4">
              <div className="flex flex-wrap gap-2">
                {group.studentIds.map(sid => {
                  const student = students.find(s => s.id === sid);
                  return student ? (
                    <div key={sid} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-full text-sm">
                      <span className="w-2 h-2 rounded-full bg-indigo-400"></span>
                      {student.name}
                    </div>
                  ) : null;
                })}
              </div>
              {group.studentIds.length === 0 && (
                <p className="text-gray-400 text-sm italic">No students assigned.</p>
              )}
            </div>
          </div>
        ))}

        {groups.length === 0 && (
          <div className="col-span-full text-center py-12 text-gray-400 bg-white rounded-xl border border-dashed border-gray-300">
            <Users size={48} className="mx-auto mb-3 opacity-20" />
            <p>No groups created yet. Create one manually.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Group, CalendarEvent } from '../types';
import { Calendar as CalendarIcon, Clock, Plus, X } from 'lucide-react';

interface SchedulerProps {
  groups: Group[];
  events: CalendarEvent[];
  setEvents: React.Dispatch<React.SetStateAction<CalendarEvent[]>>;
}

export const Scheduler: React.FC<SchedulerProps> = ({ groups, events, setEvents }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newEvent, setNewEvent] = useState<Partial<CalendarEvent>>({
    title: '',
    startTime: '',
    durationMinutes: 60,
    type: 'class',
    description: ''
  });

  const handleAddEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (newEvent.title && newEvent.startTime) {
       setEvents(prev => [...prev, {
         id: crypto.randomUUID(),
         title: newEvent.title!,
         startTime: newEvent.startTime!,
         durationMinutes: newEvent.durationMinutes || 60,
         type: newEvent.type as any || 'class',
         description: newEvent.description,
         groupId: newEvent.groupId
       }]);
       setIsAdding(false);
       setNewEvent({ title: '', startTime: '', durationMinutes: 60, type: 'class', description: '' });
    }
  };

  const getEventColor = (type: CalendarEvent['type']) => {
    switch (type) {
      case 'class': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'meeting': return 'bg-purple-100 text-purple-700 border-purple-200';
      case 'activity': return 'bg-green-100 text-green-700 border-green-200';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  // Sort events by time
  const sortedEvents = [...events].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Weekly Scheduler</h2>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex items-center justify-between mb-6">
          <h3 className="font-semibold text-lg text-gray-700 flex items-center gap-2">
            <CalendarIcon size={20} />
            Upcoming Events
          </h3>
          <button 
            onClick={() => setIsAdding(true)}
            className="text-sm text-indigo-600 font-medium hover:underline flex items-center gap-1"
          >
            <Plus size={16} /> Add Manual Event
          </button>
        </div>

        <div className="space-y-4">
          {sortedEvents.length === 0 ? (
             <p className="text-center text-gray-400 py-10 italic">No upcoming events scheduled.</p>
          ) : (
            sortedEvents.map(event => {
              const date = new Date(event.startTime);
              const group = groups.find(g => g.id === event.groupId);

              return (
                <div key={event.id} className={`p-4 rounded-lg border-l-4 ${getEventColor(event.type)} bg-opacity-30 border-opacity-50 flex flex-col md:flex-row md:items-center justify-between gap-4`}>
                  <div className="flex items-start gap-4">
                    <div className="bg-white bg-opacity-60 rounded-lg p-2 text-center min-w-[60px]">
                      <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('en-US', { month: 'short' })}</span>
                      <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-800">{event.title}</h4>
                      <div className="flex items-center gap-3 text-sm text-gray-600 mt-1">
                        <span className="flex items-center gap-1"><Clock size={14} /> {date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} ({event.durationMinutes} min)</span>
                        {group && <span className="px-2 py-0.5 bg-gray-200 rounded text-xs">{group.name}</span>}
                      </div>
                      {event.description && <p className="text-sm text-gray-500 mt-2">{event.description}</p>}
                    </div>
                  </div>
                  <span className={`text-xs font-bold px-2 py-1 rounded uppercase tracking-wide self-start md:self-center ${getEventColor(event.type).split(' ')[1]}`}>
                    {event.type}
                  </span>
                </div>
              );
            })
          )}
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">Add Event</h3>
              <button onClick={() => setIsAdding(false)} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleAddEvent} className="space-y-4">
               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Event Title</label>
                  <input
                    required
                    type="text"
                    value={newEvent.title}
                    onChange={e => setNewEvent({...newEvent, title: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Start Time</label>
                    <input
                      required
                      type="datetime-local"
                      value={newEvent.startTime}
                      onChange={e => setNewEvent({...newEvent, startTime: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Duration (min)</label>
                    <input
                      required
                      type="number"
                      value={newEvent.durationMinutes}
                      onChange={e => setNewEvent({...newEvent, durationMinutes: Number(e.target.value)})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                      <select
                        value={newEvent.type}
                        onChange={e => setNewEvent({...newEvent, type: e.target.value as any})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      >
                        <option value="class">Class</option>
                        <option value="meeting">Meeting</option>
                        <option value="activity">Activity</option>
                      </select>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Group (Optional)</label>
                      <select
                        value={newEvent.groupId || ''}
                        onChange={e => setNewEvent({...newEvent, groupId: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      >
                        <option value="">None</option>
                        {groups.map(g => (
                          <option key={g.id} value={g.id}>{g.name}</option>
                        ))}
                      </select>
                   </div>
               </div>
               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                  <textarea
                    value={newEvent.description}
                    onChange={e => setNewEvent({...newEvent, description: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    rows={2}
                  />
               </div>
               <div className="flex justify-end gap-3 pt-2">
                 <button type="button" onClick={() => setIsAdding(false)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg">Cancel</button>
                 <button type="submit" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">Save Event</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Users, Calendar, Settings, BookOpen, GraduationCap, School } from 'lucide-react';
import { MOCK_STUDENTS, MOCK_GROUPS, MOCK_EVENTS, MOCK_TEACHERS } from './constants';
import { Student, Group, CalendarEvent, Teacher, ViewState } from './types';
import { StudentList } from './components/StudentList';
import { TeacherList } from './components/TeacherList';
import { TeacherDetails } from './components/TeacherDetails';
import { GroupManager } from './components/GroupManager';
import { GroupDetails } from './components/GroupDetails';
import { Scheduler } from './components/Scheduler';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);

  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(MOCK_TEACHERS);
  const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
  const [events, setEvents] = useState<CalendarEvent[]>(MOCK_EVENTS);

  // Computed Data
  const selectedTeacher = selectedTeacherId ? teachers.find(t => t.id === selectedTeacherId) || null : null;
  const selectedGroup = selectedGroupId ? groups.find(g => g.id === selectedGroupId) || null : null;

  // Computed Dashboard Stats
  const avgGrade = Math.round(students.reduce((acc, curr) => acc + curr.grade, 0) / students.length);
  const lowPerformance = students.filter(s => s.grade < 70).length;
  const upcomingEventsCount = events.length;

  const handleTeacherSelect = (teacher: Teacher) => {
    setSelectedTeacherId(teacher.id);
  };

  const handleBackToTeacherList = () => {
    setSelectedTeacherId(null);
  };

  const handleGroupSelect = (group: Group) => {
    setSelectedGroupId(group.id);
  }

  const handleUpdateGroup = (updatedGroup: Group) => {
    setGroups(prev => prev.map(g => g.id === updatedGroup.id ? updatedGroup : g));
  };

  const handleAddStudent = (studentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...studentData,
      id: crypto.randomUUID()
    };
    setStudents(prev => [...prev, newStudent]);
  };

  // Reset selected items when changing main views
  const handleViewChange = (newView: ViewState) => {
    setView(newView);
    setSelectedTeacherId(null);
    setSelectedGroupId(null);
  };

  const renderContent = () => {
    switch (view) {
      case 'students':
        return (
          <StudentList 
            students={students} 
            onDelete={(id) => setStudents(s => s.filter(st => st.id !== id))} 
            onAdd={handleAddStudent}
          />
        );
      case 'teachers':
        if (selectedTeacher) {
          return (
            <TeacherDetails 
              teacher={selectedTeacher} 
              groups={groups} 
              events={events}
              students={students}
              onBack={handleBackToTeacherList} 
            />
          );
        }
        return (
          <TeacherList 
            teachers={teachers} 
            onDelete={(id) => setTeachers(t => t.filter(tch => tch.id !== id))} 
            onSelect={handleTeacherSelect}
          />
        );
      case 'groups':
        if (selectedGroup) {
          return (
            <GroupDetails
              group={selectedGroup}
              students={students}
              teachers={teachers}
              events={events}
              onBack={() => setSelectedGroupId(null)}
              onUpdateGroup={handleUpdateGroup}
            />
          );
        }
        return (
          <GroupManager 
            students={students} 
            groups={groups} 
            setGroups={setGroups} 
            onSelect={handleGroupSelect}
          />
        );
      case 'scheduler':
        return <Scheduler groups={groups} events={events} setEvents={setEvents} />;
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-gray-800">Dashboard Overview</h2>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-blue-100 text-blue-600 rounded-lg">
                    <GraduationCap size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Total Students</p>
                    <p className="text-2xl font-bold text-gray-800">{students.length}</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-green-100 text-green-600 rounded-lg">
                    <BookOpen size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Class Average</p>
                    <p className="text-2xl font-bold text-gray-800">{avgGrade}%</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-purple-100 text-purple-600 rounded-lg">
                    <Calendar size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Upcoming Events</p>
                    <p className="text-2xl font-bold text-gray-800">{upcomingEventsCount}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Quick Actions / Alerts */}
            <div className="grid grid-cols-1 gap-6">
               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                  <h3 className="font-semibold text-gray-800 mb-4">Attention Needed</h3>
                  {lowPerformance > 0 ? (
                    <div className="p-4 bg-red-50 border border-red-100 rounded-lg text-red-700 text-sm">
                      {lowPerformance} student(s) have grades below 70%. Consider scheduling remedial sessions.
                    </div>
                  ) : (
                    <p className="text-gray-500 text-sm">Everyone is doing great! No immediate alerts.</p>
                  )}
               </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 hidden md:flex flex-col fixed h-full z-10">
        <div className="p-6 border-b border-gray-100">
          <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl">
            <BookOpen size={24} />
            <span>EduTrack AI</span>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-1">
          <button 
            onClick={() => handleViewChange('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'dashboard' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </button>
          <button 
            onClick={() => handleViewChange('students')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'students' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
          >
            <Users size={20} />
            Students
          </button>
          <button 
            onClick={() => handleViewChange('teachers')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'teachers' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
          >
            <School size={20} />
            Teachers
          </button>
