import React, { useState } from 'react';
import { Student } from './types'; // Assuming types.ts contains type definitions

interface StudentListProps {
  students: Student[];
  onAdd: (newStudent: Student) => void;
}

const StudentList: React.FC<StudentListProps> = ({ students, onAdd }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newStudent, setNewStudent] = useState<Student>({
    id: '',
    name: '',
    birthDate: '',
    email: '',
    phone: '',
    note: '',
    grade: 0,
    behaviorScore: 10,
    interests: '',
    password: '',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewStudent({ ...newStudent, [name]: value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
      ...newStudent,
      id: Math.random().toString(36).substring(2, 15), // Basic ID generation
    });
    setNewStudent({
      id: '',
      name: '',
      birthDate: '',
      email: '',
      phone: '',
      note: '',
      grade: 0,
      behaviorScore: 10,
      interests: '',
      password: '',
    });
    setIsAdding(false);
  };

  return (
    <div>
      <h2>Student List</h2>
      <button onClick={() => setIsAdding(true)}>Add Student</button>

      {isAdding && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0, 0, 0, 0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <div style={{ backgroundColor: 'white', padding: '20px', borderRadius: '8px', width: '500px' }}>
            <h3>Add New Student</h3>
            <form onSubmit={handleSubmit}>
              {/* Personal Information */}
              <label>Name: <input type="text" name="name" value={newStudent.name} onChange={handleInputChange} required /></label><br />
              <label>Birth Date: <input type="date" name="birthDate" value={newStudent.birthDate} onChange={handleInputChange} /></label><br />
              <label>Email: <input type="email" name="email" value={newStudent.email} onChange={handleInputChange} /></label><br />
              <label>Phone: <input type="tel" name="phone" value={newStudent.phone} onChange={handleInputChange} /></label><br />
              <label>Note: <textarea name="note" value={newStudent.note} onChange={handleInputChange} /></label><br />

              {/* Password */}
              <label>Password: <input type="password" name="password" value={newStudent.password} onChange={handleInputChange} required /></label><br />

              <button type="submit">Add Student</button>
              <button type="button" onClick={() => setIsAdding(false)}>Cancel</button>
            </form>
          </div>
        </div>
      )}

      <ul>
        {students.map(student => (
          <li key={student.id}>
            {student.name} - {student.email}
          </li>
        ))}
      </ul>
    </div>
  );
};

export default StudentList;
```


