import React, { useState } from 'react';
import { LayoutDashboard, Users, Calendar, Settings, BookOpen, GraduationCap, School, LogOut, TrendingUp, Star, Mail, Phone, Clock } from 'lucide-react';
import { MOCK_STUDENTS, MOCK_GROUPS, MOCK_EVENTS, MOCK_TEACHERS } from './constants';
import { Student, Group, CalendarEvent, Teacher, ViewState } from './types';
import { StudentList } from './components/StudentList';
import { TeacherList } from './components/TeacherList';
import { TeacherDetails } from './components/TeacherDetails';
import { GroupManager } from './components/GroupManager';
import { GroupDetails } from './components/GroupDetails';
import { Scheduler } from './components/Scheduler';
import { Login } from './components/Login';
import { AdminSettings } from './components/AdminSettings';

interface AuthUser {
  id: string;
  name: string;
  role: 'admin' | 'teacher' | 'student';
  email: string;
}

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<AuthUser | null>(null);

  // Admin Credentials State
  const [adminCredentials, setAdminCredentials] = useState({
    name: 'Administrator',
    email: 'admin@mosquestrack.com',
    password: 'admin123'
  });

  const [view, setView] = useState<ViewState>('dashboard');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);

  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(MOCK_TEACHERS);
  const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
  const [events, setEvents] = useState<CalendarEvent[]>(MOCK_EVENTS);

  // Computed Data
  const selectedTeacher = selectedTeacherId ? teachers.find(t => t.id === selectedTeacherId) || null : null;
  const selectedGroup = selectedGroupId ? groups.find(g => g.id === selectedGroupId) || null : null;

  // Computed Dashboard Stats
  const avgGrade = Math.round(students.reduce((acc, curr) => acc + curr.grade, 0) / students.length);
  const lowPerformance = students.filter(s => s.grade < 70).length;
  const upcomingEventsCount = events.length;

  const handleLogin = (user: AuthUser) => {
    setCurrentUser(user);
    // Reset views
    setView('dashboard'); 
    setSelectedTeacherId(null);
    setSelectedGroupId(null);
  };

