import React, { useState } from 'react';
import { Student, Group, CalendarEvent } from '../types';
import { ArrowLeft, Mail, Phone, Calendar, Users, UserCog, Lock, Save, Check, User, TrendingUp, Star, UserCheck, BookOpen, Clock, Plus, X, LogOut } from 'lucide-react';

interface StudentDetailsProps {
  student: Student;
  groups: Group[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdate: (student: Student) => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'groups' | 'schedule' | 'settings';

export const StudentDetails: React.FC<StudentDetailsProps> = ({ student, groups, events, onBack, onUpdate, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isEnrolling, setIsEnrolling] = useState(false);
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const [formData, setFormData] = useState({
    name: student.name,
    email: student.email || '',
    phone: student.phone || '',
    password: student.password || '',
    parentName: student.parentName || '',
    parentPhone: student.parentPhone || '',
    parentEmail: student.parentEmail || '',
    grade: student.grade,
    behaviorScore: student.behaviorScore,
    notes: student.notes || ''
  });
  const [isSaved, setIsSaved] = useState(false);

  // Filter data
  const studentGroups = groups.filter(g => g.studentIds.includes(student.id));
  const availableGroups = groups.filter(g => !g.studentIds.includes(student.id));
  const groupIds = studentGroups.map(g => g.id);
  const studentEvents = events
    .filter(e => e.groupId && groupIds.includes(e.groupId))
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate({
      ...student,
      ...formData,
      // Ensure numeric types
      grade: Number(formData.grade),
      behaviorScore: Number(formData.behaviorScore)
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleEnroll = () => {
    if (selectedGroupId) {
      const groupToUpdate = groups.find(g => g.id === selectedGroupId);
      if (groupToUpdate) {
        onUpdateGroup({
          ...groupToUpdate,
          studentIds: [...groupToUpdate.studentIds, student.id]
        });
        setSelectedGroupId('');
        setIsEnrolling(false);
      }
    }
  };

  const handleUnenroll = (group: Group) => {
    if(window.confirm(`Are you sure you want to remove ${student.name} from ${group.name}?`)) {
        onUpdateGroup({
            ...group,
            studentIds: group.studentIds.filter(id => id !== student.id)
        });
    }
  };

  return (
    <div className="space-y-6">
       {/* Header */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
            onClick={onBack} 
            className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
          >
            <ArrowLeft size={18} />
            Back to Directory
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
           <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             {student.name.charAt(0)}
           </div>
           <div>
             <h1 className="text-3xl font-bold text-gray-800">{student.name}</h1>
             <div className="flex flex-wrap gap-4 mt-2 text-gray-600">
               {student.email && <span className="flex items-center gap-1"><Mail size={16} /> {student.email}</span>}
               {student.phone && <span className="flex items-center gap-1"><Phone size={16} /> {student.phone}</span>}
               <span className="flex items-center gap-1"><Calendar size={16} /> Age: {student.age || 'N/A'}</span>
             </div>
           </div>
        </div>
       </div>

       {/* Tabs */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="flex border-b border-gray-200 overflow-x-auto">
             <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Details
          </button>
          <button 
            onClick={() => setActiveTab('groups')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'groups' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Groups
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'schedule' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Schedule
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'settings' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Settings
          </button>
          </div>

          <div className="p-6 min-h-[300px]">
             {activeTab === 'details' && (
                 <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                             <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <TrendingUp size={18} className="text-indigo-500"/> Performance
                             </h3>
                             <div className="space-y-4">
                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Grade</span>
                                        <span className="font-bold">{student.grade}%</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-indigo-600 h-2 rounded-full" style={{width: `${student.grade}%`}}></div>
                                    </div>
                                </div>
                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Behavior Score</span>
                                        <span className="font-bold">{student.behaviorScore}/10</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-green-500 h-2 rounded-full" style={{width: `${student.behaviorScore * 10}%`}}></div>
                                    </div>
                                </div>
                             </div>
                        </div>

                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                            <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <UserCheck size={18} className="text-indigo-500"/> Parent/Guardian
                             </h3>
                             <ul className="space-y-3 text-sm">
                                <li className="flex gap-2">
                                    <User size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Name:</span>
                                    <span className="font-medium text-gray-800">{student.parentName || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Phone size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Phone:</span>
                                    <span className="font-medium text-gray-800">{student.parentPhone || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Mail size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Email:</span>
                                    <span className="font-medium text-gray-800">{student.parentEmail || 'N/A'}</span>
                                </li>
                             </ul>
                        </div>
                    </div>

                    <div className="p-4 bg-yellow-50 rounded-lg border border-yellow-100">
                        <h3 className="font-semibold text-gray-800 mb-2">Notes</h3>
                        <p className="text-sm text-gray-700">{student.notes || 'No additional notes.'}</p>
                    </div>
                 </div>
             )}

             {activeTab === 'groups' && (
                 <div className="space-y-4">
                  <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-800">Enrolled Groups</h3>
                    <button 
                        onClick={() => setIsEnrolling(!isEnrolling)}
                        className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition ${isEnrolling ? 'bg-gray-100 text-gray-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
                    >
                        {isEnrolling ? <X size={16} /> : <Plus size={16} />}
                        {isEnrolling ? 'Cancel' : 'Enroll in Group'}
                    </button>
                  </div>

                  {isEnrolling && (
                    <div className="bg-gray-50 p-4 rounded-xl border border-indigo-100 mb-6 animate-[fadeIn_0.2s_ease-out]">
                        <h4 className="font-semibold text-gray-700 mb-3 text-sm">Select a group to enroll in:</h4>
                        {availableGroups.length === 0 ? (
                            <div className="text-gray-500 italic text-sm">Student is already in all available groups.</div>
                        ) : (
                            <div className="flex flex-col sm:flex-row gap-3">
                                <select
                                    value={selectedGroupId}
                                    onChange={(e) => setSelectedGroupId(e.target.value)}
                                    className="flex-1 p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-sm"
                                >
                                    <option value="">-- Select Group --</option>
                                    {availableGroups.map(g => (
                                        <option key={g.id} value={g.id}>{g.name}</option>
                                    ))}
                                </select>
                                <button
                                    onClick={handleEnroll}
                                    disabled={!selectedGroupId}
                                    className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
                                >
                                    Enroll
                                </button>
                            </div>
                        )}
                    </div>
                  )}

                  {studentGroups.length === 0 ? (
                    <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                      <Users size={32} className="mx-auto mb-2 opacity-30" />
                      <p>Student is not enrolled in any groups.</p>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {studentGroups.map(group => (
                             <div key={group.id} className="border border-gray-200 rounded-lg p-4 hover:border-indigo-200 transition bg-white flex justify-between items-start group">
                                <div>
                                    <h4 className="font-bold text-indigo-700 flex items-center gap-2">
                                        <Users size={18} /> {group.name}
                                    </h4>
                                    <p className="text-sm text-gray-600 mt-1">{group.description}</p>
                                </div>
                                <button 
                                    onClick={() => handleUnenroll(group)}
                                    className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                                    title="Leave Group"
                                >
                                    <LogOut size={16} />
                                </button>
                             </div>
                        ))}
                    </div>
                  )}
                 </div>
             )}

             {activeTab === 'schedule' && (
                 <div className="space-y-4">
                    <h3 className="font-bold text-gray-800 mb-4">Upcoming Schedule</h3>
                    {studentEvents.length === 0 ? (
                        <p className="text-gray-400 italic">No scheduled events.</p>
                    ) : (
                        <div className="space-y-3">
                            {studentEvents.map(event => {
                                const date = new Date(event.startTime);
                                const group = groups.find(g => g.id === event.groupId);
                                return (
                                    <div key={event.id} className="flex items-start gap-4 p-4 border border-gray-100 rounded-lg bg-gray-50">
                                        <div className="flex-shrink-0 w-16 text-center bg-white rounded border border-gray-200 p-2">
                                            <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('en-US', { weekday: 'short' })}</span>
                                            <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-gray-800">{event.title}</h4>
                                            <p className="text-sm text-gray-600 flex items-center gap-2 mt-1">
                                                <Clock size={14} /> 
                                                {date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} ({event.durationMinutes} min)
                                            </p>
                                            {group && (
                                                <span className="inline-block mt-2 text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded">
                                                {group.name}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    )}
                 </div>
             )}

             {activeTab === 'settings' && (
                 <div className="max-w-2xl mx-auto">
                    <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
                        <UserCog size={24} className="text-indigo-600" />
                        Edit Student Profile
                    </h3>
                    <form onSubmit={handleUpdate} className="space-y-6">
                        <div className="space-y-4 bg-gray-50 p-6 rounded-xl border border-gray-200">
                             {/* Basic Info */}
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                                    <input type="text" required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                                    <input type="text" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                </div>
                             </div>

                             {/* Academic */}
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Grade (%)</label>
                                    <input type="number" min="0" max="100" value={formData.grade} onChange={e => setFormData({...formData, grade: Number(e.target.value)})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Behavior (0-10)</label>
                                    <input type="number" min="0" max="10" value={formData.behaviorScore} onChange={e => setFormData({...formData, behaviorScore: Number(e.target.value)})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                </div>
                             </div>

                             {/* Account */}
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                                    <input type="email" readOnly value={formData.email} className="w-full border border-gray-300 rounded-lg px-3 py-2 bg-gray-100 text-gray-500 cursor-not-allowed outline-none" />
                                    <p className="text-xs text-gray-500 mt-1">Read-only</p>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                                    <input type="text" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                </div>
                             </div>

                             {/* Parent Info */}
                             <div className="pt-4 border-t border-gray-200">
                                 <h4 className="font-semibold text-gray-700 mb-3">Parent / Guardian</h4>
                                 <div className="grid grid-cols-1 gap-4">
                                     <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Parent Name</label>
                                        <input type="text" value={formData.parentName} onChange={e => setFormData({...formData, parentName: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                     </div>
                                     <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Parent Phone</label>
                                            <input type="text" value={formData.parentPhone} onChange={e => setFormData({...formData, parentPhone: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Parent Email</label>
                                            <input type="email" value={formData.parentEmail} onChange={e => setFormData({...formData, parentEmail: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                                        </div>
                                     </div>
                                 </div>
                             </div>

                             <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                                <textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                             </div>
                        </div>

                        <div className="flex items-center gap-4">
                            <button
                                type="submit"
                                className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm flex items-center gap-2"
                            >
                                <Save size={18} />
                                Save Changes
                            </button>
                            {isSaved && (
                                <span className="text-green-600 flex items-center gap-1.5 text-sm font-medium animate-[fadeIn_0.3s_ease-out]">
                                <Check size={18} />
                                Student updated!
                                </span>
                            )}
                        </div>
                    </form>
                 </div>
             )}
          </div>
       </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Users, Calendar, Settings, BookOpen, GraduationCap, School, LogOut, TrendingUp, Star, Mail, Phone, Clock } from 'lucide-react';
import { MOCK_STUDENTS, MOCK_GROUPS, MOCK_EVENTS, MOCK_TEACHERS } from './constants';
import { Student, Group, CalendarEvent, Teacher, ViewState } from './types';
import { StudentList } from './components/StudentList';
import { StudentDetails } from './components/StudentDetails';
import { TeacherList } from './components/TeacherList';
import { TeacherDetails } from './components/TeacherDetails';
import { GroupManager } from './components/GroupManager';
import { GroupDetails } from './components/GroupDetails';
import { Scheduler } from './components/Scheduler';
import { Login } from './components/Login';
import { AdminSettings } from './components/AdminSettings';

interface AuthUser {
  id: string;
  name: string;
  role: 'admin' | 'teacher' | 'student';
  email: string;
}

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<AuthUser | null>(null);

  // Admin Credentials State
  const [adminCredentials, setAdminCredentials] = useState({
    name: 'Administrator',
    email: 'admin@mosquestrack.com',
    password: 'admin123'
  });

  const [view, setView] = useState<ViewState>('dashboard');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);

  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [teachers, setTeachers] = useState<Teacher[]>(MOCK_TEACHERS);
  const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
  const [events, setEvents] = useState<CalendarEvent[]>(MOCK_EVENTS);

  // Computed Data
  const selectedTeacher = selectedTeacherId ? teachers.find(t => t.id === selectedTeacherId) || null : null;
  const selectedStudent = selectedStudentId ? students.find(s => s.id === selectedStudentId) || null : null;
  const selectedGroup = selectedGroupId ? groups.find(g => g.id === selectedGroupId) || null : null;

  // Computed Dashboard Stats
  const avgGrade = Math.round(students.reduce((acc, curr) => acc + curr.grade, 0) / students.length);
  const lowPerformance = students.filter(s => s.grade < 70).length;
  const upcomingEventsCount = events.length;

  const handleLogin = (user: AuthUser) => {
    setCurrentUser(user);
    // Reset views
    setView('dashboard'); 
    setSelectedTeacherId(null);
    setSelectedStudentId(null);
    setSelectedGroupId(null);
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleTeacherSelect = (teacher: Teacher) => {
    setSelectedTeacherId(teacher.id);
  };

  const handleBackToTeacherList = () => {
    setSelectedTeacherId(null);
  };

  const handleStudentSelect = (student: Student) => {
    setSelectedStudentId(student.id);
  };

  const handleBackToStudentList = () => {
    setSelectedStudentId(null);
  };

  const handleGroupSelect = (group: Group) => {
    setSelectedGroupId(group.id);
  }

  const handleUpdateGroup = (updatedGroup: Group) => {
    setGroups(prev => prev.map(g => g.id === updatedGroup.id ? updatedGroup : g));
  };

  const handleUpdateTeacher = (updatedTeacher: Teacher) => {
    setTeachers(prev => prev.map(t => t.id === updatedTeacher.id ? updatedTeacher : t));
    // Update current user session if the teacher updates their own profile
    if (currentUser && currentUser.id === updatedTeacher.id) {
      setCurrentUser(prev => prev ? ({ ...prev, name: updatedTeacher.name, email: updatedTeacher.email }) : null);
    }
  };

  const handleUpdateStudent = (updatedStudent: Student) => {
    setStudents(prev => prev.map(s => s.id === updatedStudent.id ? updatedStudent : s));
    // Update current user session if the student updates their own profile (future proofing if students can edit)
    if (currentUser && currentUser.id === updatedStudent.id) {
        setCurrentUser(prev => prev ? ({ ...prev, name: updatedStudent.name, email: updatedStudent.email! }) : null);
    }
  }

  const handleAddStudent = (studentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...studentData,
      id: crypto.randomUUID()
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleAddTeacher = (teacherData: Omit<Teacher, 'id'>) => {
    const newTeacher: Teacher = {
      ...teacherData,
      id: crypto.randomUUID()
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  // Reset selected items when changing main views
  const handleViewChange = (newView: ViewState) => {
    setView(newView);
    setSelectedTeacherId(null);
    setSelectedStudentId(null);
    setSelectedGroupId(null);
  };

  // --- Views for Role: STUDENT ---
  const renderStudentSpace = () => {
    if (!currentUser) return null;
    const student = students.find(s => s.id === currentUser.id);
    if (!student) return <div>Student profile not found.</div>;

    // Filter events for this student (via their groups)
    const myGroupIds = groups.filter(g => g.studentIds.includes(student.id)).map(g => g.id);
    const myEvents = events.filter(e => e.groupId && myGroupIds.includes(e.groupId));

    return (
      <div className="space-y-6">
        <h2 className="text-2xl font-bold text-gray-800">My Student Space</h2>

        {/* Profile Card */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
           <div className="flex items-center gap-4 mb-4">
             <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-2xl">
                {student.name.charAt(0)}
             </div>
             <div>
               <h3 className="text-xl font-bold text-gray-800">{student.name}</h3>
               <p className="text-gray-500">{student.email}</p>
             </div>
           </div>

           <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-4 bg-gray-50 p-4 rounded-lg">
              <div>
                 <span className="block text-xs text-gray-500 uppercase">Grade</span>
                 <span className={`text-lg font-bold ${student.grade >= 90 ? 'text-green-600' : 'text-gray-800'}`}>{student.grade}%</span>
              </div>
              <div>
                 <span className="block text-xs text-gray-500 uppercase">Behavior</span>
                 <span className="text-lg font-bold text-gray-800">{student.behaviorScore}/10</span>
              </div>
              <div>
                 <span className="block text-xs text-gray-500 uppercase">Groups</span>
                 <span className="text-lg font-bold text-gray-800">{myGroupIds.length}</span>
              </div>
              <div>
                 <span className="block text-xs text-gray-500 uppercase">Age</span>
                 <span className="text-lg font-bold text-gray-800">{student.age || 'N/A'}</span>
              </div>
           </div>
        </div>

        {/* Schedule */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
          <h3 className="font-semibold text-lg text-gray-800 mb-4 flex items-center gap-2">
            <Calendar size={20} className="text-indigo-600"/> My Upcoming Classes
          </h3>
          {myEvents.length === 0 ? (
            <p className="text-gray-400 italic">No upcoming classes scheduled.</p>
          ) : (
             <div className="space-y-3">
               {myEvents.map(event => {
                 const date = new Date(event.startTime);
                 const group = groups.find(g => g.id === event.groupId);
                 return (
                   <div key={event.id} className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg border border-gray-100">
                      <div className="text-center bg-white p-2 rounded border border-gray-200 min-w-[60px]">
                        <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('en-US', { weekday: 'short' })}</span>
                        <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                      </div>
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-800">{event.title}</h4>
                        <div className="flex items-center gap-3 text-sm text-gray-600">
                          <span className="flex items-center gap-1"><Clock size={14} /> {date.toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'})}</span>
                          {group && <span className="bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded text-xs">{group.name}</span>}
                        </div>
                      </div>
                   </div>
                 )
               })}
             </div>
          )}
        </div>
      </div>
    );
  };

  // --- Views for Role: TEACHER ---
  const renderTeacherSpace = () => {
    if (!currentUser) return null;
    const teacher = teachers.find(t => t.id === currentUser.id);
    if (!teacher) return <div>Teacher profile not found.</div>;

    // Reuse TeacherDetails but standalone
    return (
      <TeacherDetails 
        teacher={teacher}
        groups={groups}
        events={events}
        students={students}
        onBack={() => {}} 
        onUpdate={handleUpdateTeacher}
        standalone={true}
      />
    );
  };

  const renderAdminContent = () => {
    switch (view) {
      case 'students':
        if (selectedStudent) {
            return (
                <StudentDetails
                    student={selectedStudent}
                    groups={groups}
                    events={events}
                    onBack={handleBackToStudentList}
                    onUpdate={handleUpdateStudent}
                    onUpdateGroup={handleUpdateGroup}
                />
            );
        }
        return (
          <StudentList 
            students={students} 
            onDelete={(id) => setStudents(s => s.filter(st => st.id !== id))} 
            onAdd={handleAddStudent}
            onSelect={handleStudentSelect}
          />
        );
      case 'teachers':
        if (selectedTeacher) {
          return (
            <TeacherDetails 
              teacher={selectedTeacher} 
              groups={groups} 
              events={events}
              students={students}
              onBack={handleBackToTeacherList} 
              onUpdate={handleUpdateTeacher}
            />
          );
        }
        return (
          <TeacherList 
            teachers={teachers} 
            onDelete={(id) => setTeachers(t => t.filter(tch => tch.id !== id))} 
            onSelect={handleTeacherSelect}
            onAdd={handleAddTeacher}
          />
        );
      case 'groups':
        if (selectedGroup) {
          return (
            <GroupDetails
              group={selectedGroup}
              students={students}
              teachers={teachers}
              events={events}
              onBack={() => setSelectedGroupId(null)}
              onUpdateGroup={handleUpdateGroup}
            />
          );
        }
        return (
          <GroupManager 
            students={students} 
            groups={groups} 
            setGroups={setGroups} 
            onSelect={handleGroupSelect}
          />
        );
      case 'scheduler':
        return <Scheduler groups={groups} events={events} setEvents={setEvents} />;
      case 'settings':
        return (
          <AdminSettings 
            credentials={adminCredentials} 
            onUpdate={(newCreds) => {
              setAdminCredentials(newCreds);
              setCurrentUser(prev => prev ? ({...prev, name: newCreds.name, email: newCreds.email}) : null);
            }} 
          />
        );
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold text-gray-800">Dashboard Overview</h2>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-blue-100 text-blue-600 rounded-lg">
                    <GraduationCap size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Total Students</p>
                    <p className="text-2xl font-bold text-gray-800">{students.length}</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-green-100 text-green-600 rounded-lg">
                    <BookOpen size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Class Average</p>
                    <p className="text-2xl font-bold text-gray-800">{avgGrade}%</p>
                  </div>
                </div>
              </div>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-purple-100 text-purple-600 rounded-lg">
                    <Calendar size={24} />
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Upcoming Events</p>
                    <p className="text-2xl font-bold text-gray-800">{upcomingEventsCount}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Quick Actions / Alerts */}
            <div className="grid grid-cols-1 gap-6">
               <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                  <h3 className="font-semibold text-gray-800 mb-4">Attention Needed</h3>
                  {lowPerformance > 0 ? (
                    <div className="p-4 bg-red-50 border border-red-100 rounded-lg text-red-700 text-sm">
                      {lowPerformance} student(s) have grades below 70%. Consider scheduling remedial sessions.
                    </div>
                  ) : (
                    <p className="text-gray-500 text-sm">Everyone is doing great! No immediate alerts.</p>
                  )}
               </div>
            </div>
          </div>
        );
    }
  };

  // --- Auth Guard ---
  if (!currentUser) {
    return <Login students={students} teachers={teachers} adminCredentials={adminCredentials} onLogin={handleLogin} />;
  }

  // --- Main Layout ---
  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar - Only for ADMIN */}
      {currentUser.role === 'admin' && (
        <aside className="w-64 bg-white border-r border-gray-200 hidden md:flex flex-col fixed h-full z-10">
          <div className="p-6 border-b border-gray-100">
            <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl">
              <BookOpen size={24} />
              <span>Mosques Track</span>
            </div>
          </div>

          <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            <button 
              onClick={() => handleViewChange('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'dashboard' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <LayoutDashboard size={20} />
              Dashboard
            </button>
            <button 
              onClick={() => handleViewChange('students')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'students' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Users size={20} />
              Students
            </button>
            <button 
              onClick={() => handleViewChange('teachers')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'teachers' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <School size={20} />
              Teachers
            </button>
            <button 
              onClick={() => handleViewChange('groups')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'groups' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Users size={20} className="scale-x-[-1]" />
              Groups
            </button>
            <button 
              onClick={() => handleViewChange('scheduler')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'scheduler' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Calendar size={20} />
              Scheduler
            </button>
          </nav>

          <div className="p-4 border-t border-gray-100 space-y-1">
            <button 
              onClick={() => handleViewChange('settings')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition ${view === 'settings' ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Settings size={20} />
              Settings
            </button>
            <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 text-red-600 hover:bg-red-50 rounded-lg transition">
              <LogOut size={20} />
              Logout
            </button>
          </div>
        </aside>
      )}

      {/* Main Content */}
      <main className={`flex-1 ${currentUser.role === 'admin' ? 'md:ml-64' : ''}`}>

        {/* Header (Admin Mobile / Everyone Else Desktop) */}
        <div className="bg-white border-b border-gray-200 p-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
             {currentUser.role !== 'admin' && (
                <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl md:hidden">
                  <BookOpen size={24} />
                  <span>Mosques Track</span>
                </div>
             )}
             <span className="font-bold text-gray-700 hidden md:block">
               Welcome, {currentUser.name}
             </span>
          </div>

          <div className="flex items-center gap-4">
             {/* Admin Mobile Navigation */}
             {currentUser.role === 'admin' && (
                <div className="flex gap-4 md:hidden">
                  <button onClick={() => handleViewChange('dashboard')} className="text-gray-600"><LayoutDashboard size={20}/></button>
                  <button onClick={() => handleViewChange('students')} className="text-gray-600"><Users size={20}/></button>
                  <button onClick={() => handleViewChange('teachers')} className="text-gray-600"><School size={20}/></button>
                  <button onClick={() => handleViewChange('groups')} className="text-gray-600"><Users size={20}/></button>
                  <button onClick={() => handleViewChange('scheduler')} className="text-gray-600"><Calendar size={20}/></button>
                  <button onClick={() => handleViewChange('settings')} className="text-gray-600"><Settings size={20}/></button>
                </div>
             )}

             {/* Logout Button (Visible in header for everyone, essential for non-admins) */}
             <button onClick={handleLogout} className="flex items-center gap-2 text-sm font-medium text-red-600 hover:bg-red-50 px-3 py-1.5 rounded-lg transition">
                <LogOut size={18} />
                <span className="hidden sm:inline">Logout</span>
             </button>
          </div>
        </div>

        <div className="p-6 max-w-7xl mx-auto">
          {currentUser.role === 'admin' && renderAdminContent()}
          {currentUser.role === 'student' && renderStudentSpace()}
          {currentUser.role === 'teacher' && renderTeacherSpace()}
        </div>
      </main>
    </div>
  );
};

export default App;

export interface Student {
  id: string;
  name: string;
  grade: number; // 0-100
  behaviorScore: number; // 0-10
  interests: string[];
  notes?: string;
  birthDate?: string;
  age?: number;
  email?: string;
  password?: string;
  phone?: string;
  parentName?: string;
  parentPhone?: string;
  parentEmail?: string;
  currentSurah?: string; // Tracking progress
}

export interface Teacher {
  id: string;
  name: string;
  subject: string;
  email: string;
  password?: string;
  yearsExperience: number;
}

export interface Group {
  id: string;
  name: string;
  description: string;
  studentIds: string[];
  teacherId?: string; // Link to a teacher
}

export interface CalendarEvent {
  id: string;
  title: string;
  description?: string;
  startTime: string; // ISO string
  durationMinutes: number;
  groupId?: string; // Optional linkage to a group
  teacherId?: string; // Optional linkage to a teacher
  type: 'class' | 'meeting' | 'activity';
}

export type ViewState = 'dashboard' | 'students' | 'teachers' | 'groups' | 'scheduler' | 'settings';

import React, { useState, useEffect } from 'react';
import { Student } from '../types';
import { User, Trash2, TrendingUp, Star, AlertTriangle, Plus, X, Phone, Mail, Calendar, BookOpen, UserCheck, Lock } from 'lucide-react';
import { QURAN_SURAHS } from '../constants';

interface StudentListProps {
  students: Student[];
  onDelete: (id: string) => void;
  onAdd: (student: Omit<Student, 'id'>) => void;
  onSelect: (student: Student) => void;
}

export const StudentList: React.FC<StudentListProps> = ({ students, onDelete, onAdd, onSelect }) => {
  const [studentToDelete, setStudentToDelete] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    grade: 0,
    behaviorScore: 10,
    interests: '',
    birthDate: '',
    age: 0,
    phone: '',
    email: '',
    password: '',
    notes: '',
    parentName: '',
    parentPhone: '',
    parentEmail: '',
    currentSurah: ''
  });

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setStudentToDelete(id);
  };

  const confirmDelete = () => {
    if (studentToDelete) {
      onDelete(studentToDelete);
      setStudentToDelete(null);
    }
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const date = e.target.value;
    const age = calculateAge(date);
    setNewStudent(prev => ({ ...prev, birthDate: date, age }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
      name: newStudent.name,
      grade: Number(newStudent.grade),
      behaviorScore: Number(newStudent.behaviorScore),
      interests: newStudent.interests ? newStudent.interests.split(',').map(i => i.trim()).filter(i => i) : [],
      birthDate: newStudent.birthDate,
      age: newStudent.age,
      phone: newStudent.phone,
      email: newStudent.email,
      password: newStudent.password,
      notes: newStudent.notes,
      parentName: newStudent.parentName,
      parentPhone: newStudent.parentPhone,
      parentEmail: newStudent.parentEmail,
      currentSurah: newStudent.currentSurah
    });
    setIsAdding(false);
    // Reset form
    setNewStudent({
      name: '',
      grade: 0,
      behaviorScore: 10,
      interests: '',
      birthDate: '',
      age: 0,
      phone: '',
      email: '',
      password: '',
      notes: '',
      parentName: '',
      parentPhone: '',
      parentEmail: '',
      currentSurah: ''
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Student Directory</h2>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center gap-2"
        >
          <User size={18} />
          Add Student
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {students.map((student) => (
          <div 
            key={student.id} 
            onClick={() => onSelect(student)}
            className="bg-white p-5 rounded-xl shadow-sm border border-gray-200 hover:shadow-md transition cursor-pointer relative group"
          >
            <div className="flex items-start justify-between">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-lg">
                  {student.name.charAt(0)}
                </div>
                <div>
                  <h3 className="font-semibold text-gray-800 group-hover:text-indigo-600 transition-colors">{student.name}</h3>
                  <p className="text-xs text-gray-500">ID: {student.id}</p>
                </div>
              </div>
              <button 
                onClick={(e) => handleDeleteClick(e, student.id)}
                className="text-gray-400 hover:text-red-500 transition"
              >
                <Trash2 size={18} />
              </button>
            </div>

            <div className="mt-4 grid grid-cols-2 gap-2 text-sm">
              <div className="bg-gray-50 p-2 rounded flex flex-col">
                <span className="text-gray-500 text-xs flex items-center gap-1"><TrendingUp size={12}/> Grade</span>
                <span className={`font-semibold ${student.grade >= 90 ? 'text-green-600' : student.grade >= 70 ? 'text-yellow-600' : 'text-red-600'}`}>
                  {student.grade}%
                </span>
              </div>
              <div className="bg-gray-50 p-2 rounded flex flex-col">
                <span className="text-gray-500 text-xs flex items-center gap-1"><Star size={12}/> Behavior</span>
                <span className="font-semibold text-gray-800">{student.behaviorScore}/10</span>
              </div>
            </div>

            {student.currentSurah && (
              <div className="mt-2 bg-indigo-50 p-2 rounded flex items-center gap-2">
                 <BookOpen size={14} className="text-indigo-600" />
                 <div className="flex flex-col">
                   <span className="text-[10px] uppercase text-indigo-500 font-bold">Current Surah</span>
                   <span className="text-xs font-semibold text-indigo-800 truncate">{student.currentSurah}</span>
                 </div>
              </div>
            )}

            <div className="mt-3">
              <p className="text-xs text-gray-500 mb-1">Interests</p>
              <div className="flex flex-wrap gap-1 mb-3">
                {student.interests.map((interest, idx) => (
                  <span key={idx} className="text-xs bg-blue-50 text-blue-700 px-2 py-0.5 rounded-full">
                    {interest}
                  </span>
                ))}
              </div>

              {(student.email || student.phone) && (
                <div className="pt-3 border-t border-gray-100 flex flex-col gap-1 text-xs text-gray-500">
                   {student.email && <span className="flex items-center gap-1"><Mail size={10} /> {student.email}</span>}
                   {student.phone && <span className="flex items-center gap-1"><Phone size={10} /> {student.phone}</span>}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Confirmation Modal */}
      {studentToDelete && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6 animate-[fadeIn_0.2s_ease-out]">
             <div className="flex items-center gap-3 text-red-600 mb-4">
               <div className="bg-red-100 p-2 rounded-full">
                 <AlertTriangle size={24} />
               </div>
               <h3 className="text-xl font-bold">Delete Student?</h3>
             </div>
             <p className="text-gray-600 mb-6">
               Are you sure you want to delete this student? This action cannot be undone and will remove them from any assigned groups.
             </p>
             <div className="flex justify-end gap-3">
               <button
                 onClick={() => setStudentToDelete(null)}
                 className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
               >
                 Cancel
               </button>
               <button
                 onClick={confirmDelete}
                 className="px-4 py-2 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 transition shadow-sm"
               >
                 Delete Student
               </button>
             </div>
          </div>
        </div>
      )}

      {/* Add Student Modal */}
      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full p-6 animate-[fadeIn_0.2s_ease-out] overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">Add New Student</h3>
              <button onClick={() => setIsAdding(false)} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">

              {/* Personal Information */}
              <div className="bg-gray-50 p-4 rounded-lg border border-gray-100">
                <h4 className="font-semibold text-gray-700 mb-3 flex items-center gap-2">
                  <User size={16} className="text-indigo-600"/> Personal Information
                </h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                    <input
                      required
                      type="text"
                      value={newStudent.name}
                      onChange={e => setNewStudent({...newStudent, name: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="e.g. John Doe"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Current Surah (Progress)</label>
                    <div className="relative">
                      <BookOpen className="absolute left-3 top-2.5 text-gray-400" size={18} />
                      <select
                        value={newStudent.currentSurah}
                        onChange={e => setNewStudent({...newStudent, currentSurah: e.target.value})}
                        className="w-full pl-10 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                      >
                        <option value="">-- Select Surah --</option>
                        {QURAN_SURAHS.map(surah => (
                          <option key={surah} value={surah}>{surah}</option>
                        ))}
                      </select>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Birth Date</label>
                      <input
                        type="date"
                        value={newStudent.birthDate}
                        onChange={handleDateChange}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Age (Auto-calculated)</label>
                      <input
                        type="number"
                        readOnly
                        value={newStudent.age}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 bg-gray-100 text-gray-500 cursor-not-allowed outline-none"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                      <input
                        type="email"
                        value={newStudent.email}
                        onChange={e => setNewStudent({...newStudent, email: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="student@example.com"
                      />
                    </div>
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                      <input
                        type="password"
                        value={newStudent.password}
                        onChange={e => setNewStudent({...newStudent, password: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="Set password"
                      />
                    </div>
                  </div>

                  <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                      <input
                        type="tel"
                        value={newStudent.phone}
                        onChange={e => setNewStudent({...newStudent, phone: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="(555) 123-4567"
                      />
                  </div>

                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Note</label>
                      <textarea
                        value={newStudent.notes}
                        onChange={e => setNewStudent({...newStudent, notes: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="Any additional information..."
                        rows={2}
                      />
                  </div>
                </div>
              </div>

              {/* Parent Section */}
              <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100">
                <h4 className="font-semibold text-indigo-900 mb-3 flex items-center gap-2">
                  <UserCheck size={16} className="text-indigo-600"/> Parent / Guardian Information
                </h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Parent Name</label>
                    <input
                      type="text"
                      value={newStudent.parentName}
                      onChange={e => setNewStudent({...newStudent, parentName: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="e.g. Jane Doe"
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Email</label>
                      <input
                        type="email"
                        value={newStudent.parentEmail}
                        onChange={e => setNewStudent({...newStudent, parentEmail: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Phone</label>
                      <input
                        type="tel"
                        value={newStudent.parentPhone}
                        onChange={e => setNewStudent({...newStudent, parentPhone: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-100">
                <button
                  type="button"
                  onClick={() => setIsAdding(false)}
                  className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm"
                >
                  Save Student
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Student, Group, CalendarEvent } from '../types';
import { ArrowLeft, Mail, Phone, Calendar, Users, UserCog, Lock, Save, Check, User, TrendingUp, Star, UserCheck, BookOpen, Clock, Plus, X, LogOut } from 'lucide-react';
import { QURAN_SURAHS } from '../constants';

interface StudentDetailsProps {
  student: Student;
  groups: Group[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdate: (student: Student) => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'groups' | 'schedule' | 'settings';

export const StudentDetails: React.FC<StudentDetailsProps> = ({ student, groups, events, onBack, onUpdate, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isEnrolling, setIsEnrolling] = useState(false);
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const [formData, setFormData] = useState({
    name: student.name,
    email: student.email || '',
    phone: student.phone || '',
    password: student.password || '',
    parentName: student.parentName || '',
    parentPhone: student.parentPhone || '',
    parentEmail: student.parentEmail || '',
    grade: student.grade,
    behaviorScore: student.behaviorScore,
    notes: student.notes || '',
    currentSurah: student.currentSurah || ''
  });
  const [isSaved, setIsSaved] = useState(false);

  // Filter data
  const studentGroups = groups.filter(g => g.studentIds.includes(student.id));
  const availableGroups = groups.filter(g => !g.studentIds.includes(student.id));
  const groupIds = studentGroups.map(g => g.id);
  const studentEvents = events
    .filter(e => e.groupId && groupIds.includes(e.groupId))
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate({
      ...student,
      ...formData,
      // Ensure numeric types
      grade: Number(formData.grade),
      behaviorScore: Number(formData.behaviorScore)
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleEnroll = () => {
    if (selectedGroupId) {
      const groupToUpdate = groups.find(g => g.id === selectedGroupId);
      if (groupToUpdate) {
        onUpdateGroup({
          ...groupToUpdate,
          studentIds: [...groupToUpdate.studentIds, student.id]
        });
        setSelectedGroupId('');
        setIsEnrolling(false);
      }
    }
  };

  const handleUnenroll = (group: Group) => {
    if(window.confirm(`Are you sure you want to remove ${student.name} from ${group.name}?`)) {
        onUpdateGroup({
            ...group,
            studentIds: group.studentIds.filter(id => id !== student.id)
        });
    }
  };

  return (
    <div className="space-y-6">
       {/* Header */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
            onClick={onBack} 
            className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
          >
            <ArrowLeft size={18} />
            Back to Directory
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
           <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             {student.name.charAt(0)}
           </div>
           <div>
             <h1 className="text-3xl font-bold text-gray-800">{student.name}</h1>
             <div className="flex flex-wrap gap-4 mt-2 text-gray-600">
               {student.email && <span className="flex items-center gap-1"><Mail size={16} /> {student.email}</span>}
               {student.phone && <span className="flex items-center gap-1"><Phone size={16} /> {student.phone}</span>}
               <span className="flex items-center gap-1"><Calendar size={16} /> Age: {student.age || 'N/A'}</span>
             </div>
           </div>
        </div>
       </div>

       {/* Tabs */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="flex border-b border-gray-200 overflow-x-auto">
             <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Details
          </button>
          <button 
            onClick={() => setActiveTab('groups')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'groups' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Groups
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'schedule' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Schedule
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'settings' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Settings
          </button>
          </div>

          <div className="p-6 min-h-[300px]">
             {activeTab === 'details' && (
                 <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                             <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <TrendingUp size={18} className="text-indigo-500"/> Performance & Progress
                             </h3>
                             <div className="space-y-4">
                                {student.currentSurah && (
                                  <div className="mb-4 p-3 bg-indigo-50 rounded-lg border border-indigo-100 flex items-center gap-3">
                                      <div className="p-2 bg-indigo-100 text-indigo-600 rounded-full">
                                        <BookOpen size={20} />
                                      </div>
                                      <div>
                                        <span className="block text-xs text-indigo-500 uppercase font-bold">Current Surah</span>
                                        <span className="block text-lg font-bold text-indigo-900">{student.currentSurah}</span>
                                      </div>
                                  </div>
                                )}
                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Grade</span>
                                        <span className="font-bold">{student.grade}%</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-indigo-600 h-2 rounded-full" style={{width: `${student.grade}%`}}></div>
                                    </div>
                                </div>
                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Behavior Score</span>
                                        <span className="font-bold">{student.behaviorScore}/10</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-green-500 h-2 rounded-full" style={{width: `${student.behaviorScore * 10}%`}}></div>
                                    </div>
                                </div>
                             </div>
                        </div>

                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                            <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <UserCheck size={18} className="text-indigo-500"/> Parent/Guardian
                             </h3>
                             <ul className="space-y-3 text-sm">
                                <li className="flex gap-2">
                                    <User size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Name:</span>
                                    <span className="font-medium text-gray-800">{student.parentName || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Phone size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Phone:</span>
                                    <span className="font-medium text-gray-800">{student.parentPhone || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Mail size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Email:</span>
                                    <span className="font-medium text-gray-800">{student.parentEmail || 'N/A'}</span>
                                </li>
                             </ul>
                        </div>
                    </div>

                    <div className="p-4 bg-yellow-50 rounded-lg border border-yellow-100">
                        <h3 className="font-semibold text-gray-800 mb-2">Notes</h3>
                        <p className="text-sm text-gray-700">{student.notes || 'No additional notes.'}</p>
                    </div>
                 </div>
             )}

             {activeTab === 'groups' && (
                 <div className="space-y-4">
                  <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-800">Enrolled Groups</h3>
                    <button 
                        onClick={() => setIsEnrolling(!isEnrolling)}
                        className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition ${isEnrolling ? 'bg-gray-100 text-gray-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
                    >
                        {isEnrolling ? <X size={16} /> : <Plus size={16} />}
                        {isEnrolling ? 'Cancel' : 'Enroll in Group'}
                    </button>
                  </div>

                  {isEnrolling && (
                    <div className="bg-gray-50 p-4 rounded-xl border border-indigo-100 mb-6 animate-[fadeIn_0.2s_ease-out]">
                        <h4 className="font-semibold text-gray-700 mb-3 text-sm">Select a group to enroll in:</h4>
                        {availableGroups.length === 0 ? (
                            <div className="text-gray-500 italic text-sm">Student is already in all available groups.</div>
                        ) : (
                            <div className="flex flex-col sm:flex-row gap-3">
                                <select
                                    value={selectedGroupId}
                                    onChange={(e) => setSelectedGroupId(e.target.value)}
                                    className="flex-1 p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-sm"
                                >
                                    <option value="">-- Select Group --</option>
                                    {availableGroups.map(g => (
                                        <option key={g.id} value={g.id}>{g.name}</option>
                                    ))}
                                </select>
                                <button
                                    onClick={handleEnroll}
                                    disabled={!selectedGroupId}
                                    className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
                                >
                                    Enroll
                                </button>
                            </div>
                        )}
                    </div>
                  )}

                  {studentGroups.length === 0 ? (
                    <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                      <Users size={32} className="mx-auto mb-2 opacity-30" />
                      <p>Student is not enrolled in any groups.</p>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {studentGroups.map(group => (
                             <div key={group.id} className="border border-gray-200 rounded-lg p-4 hover:border-indigo-200 transition bg-white flex justify-between items-start group">
                                <div>
                                    <h4 className="font-bold text-indigo-700 flex items-center gap-2">
                                        <Users size={18} /> {group.name}
                                    </h4>
                                    <p className="text-sm text-gray-600 mt-1">{group.description}</p>
                                </div>
                                <button 
                                    onClick={() => handleUnenroll(group)}
                                    className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                                    title="Leave Group"
                                >
                                    <LogOut size={16} />
                                </button>
                             </div>
                        ))}
                    </div>
                  )}
                 </div>
             )}

             {activeTab === 'schedule' && (
                 <div className="space-y-4">
                    <h3 className="font-bold text-gray-800 mb-4">Upcoming Schedule</h3>
                    {studentEvents.length === 0 ? (
                        <p className="text-gray-400 italic">No scheduled events.</p>
                    ) : (
                        <div className="space-y-3">
                            {studentEvents.map(event => {
                                const date = new Date(event.startTime);
                                const group = groups.find(g => g.id === event.groupId);
                                return (
                                    <div key={event.id} className="flex items-start gap-4 p-4 border border-gray-100 rounded-lg bg-gray-50">
                                        <div className="flex-shrink-0 w-16 text-center bg-white rounded border border-gray-200 p-2">
                                            <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('en-US', { weekday: 'short' })}</span>
                                            <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-gray-800">{event.title}</h4>
                                            <p className="text-sm text-gray-600 flex items-center gap-2 mt-1">
                                                <Clock size={14} /> 
                                                {date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} ({event.durationMinutes} min)
                                            </p>
                                            {group && (
                                                <span className="inline-block mt-2 text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded">
                                                {group.name}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    )}
                 </div>
             )}

             {activeTab === 'settings' && (
                 <div className="max-w-2xl mx-auto">
                    <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
                        <UserCog size={24} className="text-indigo-600" />
                        Edit Student Profile
                    </h3>
                    <form onSubmit={handleUpdate} className="space-y-6">
                        <div className="space-y-4 bg-gray-50 p-6 rounded-xl border border-gray-200">
                             {/* Basic Info */}
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
