    setIsAdding(false);
    // Reset form
    setNewStudent({
      name: '',
      grade: 0,
      behaviorScore: 10,
      interests: '',
      birthDate: '',
      age: 0,
      phone: '',
      email: '',
      password: '',
      notes: '',
      parentName: '',
      parentPhone: '',
      parentEmail: '',
      currentSurah: '',
