             <p className="text-gray-600 mb-6">
               Are you sure you want to delete this student? This action cannot be undone and will remove them from any assigned groups.
             </p>
             <div className="flex justify-end gap-3">
               <button
                 onClick={() => setStudentToDelete(null)}
                 className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
               >
                 Cancel
               </button>
               <button
                 onClick={confirmDelete}
                 className="px-4 py-2 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 transition shadow-sm"
               >
                 Delete Student
               </button>
             </div>
          </div>
        </div>
      )}

      {/* Add Student Modal */}
      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full p-6 animate-[fadeIn_0.2s_ease-out] overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">Add New Student</h3>
              <button onClick={() => setIsAdding(false)} className="text-gray-400 hover:text-gray-600">
