import React, { useState, useEffect } from 'react';
import { Student } from '../types';
import { User, Trash2, TrendingUp, Star, AlertTriangle, Plus, X, Phone, Mail, Calendar, BookOpen, UserCheck, Lock } from 'lucide-react';
import { QURAN_SURAHS } from '../constants';

interface StudentListProps {
  students: Student[];
  onDelete: (id: string) => void;
  onAdd: (student: Omit<Student, 'id'>) => void;
  onSelect: (student: Student) => void;
}

export const StudentList: React.FC<StudentListProps> = ({ students, onDelete, onAdd, onSelect }) => {
  const [studentToDelete, setStudentToDelete] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    grade: 0,
    behaviorScore: 10,
    interests: '',
    birthDate: '',
    age: 0,
    phone: '',
    email: '',
    password: '',
    notes: '',
    parentName: '',
    parentPhone: '',
    parentEmail: '',
    currentSurah: '',
    currentAyah: 1
  });

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setStudentToDelete(id);
  };

  const confirmDelete = () => {
    if (studentToDelete) {
      onDelete(studentToDelete);
      setStudentToDelete(null);
    }
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const date = e.target.value;
    const age = calculateAge(date);
    setNewStudent(prev => ({ ...prev, birthDate: date, age }));
  };

  const getProgress = (surah: string | undefined) => {
    if (!surah) return 0;
    const index = QURAN_SURAHS.indexOf(surah);
    // Simple progress calculation: (Surah Index + 1) / 114 * 100
    return index !== -1 ? Math.round(((index + 1) / 114) * 100) : 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
      name: newStudent.name,
      grade: Number(newStudent.grade),
      behaviorScore: Number(newStudent.behaviorScore),
      interests: newStudent.interests ? newStudent.interests.split(',').map(i => i.trim()).filter(i => i) : [],
      birthDate: newStudent.birthDate,
      age: newStudent.age,
      phone: newStudent.phone,
      email: newStudent.email,
      password: newStudent.password,
      notes: newStudent.notes,
      parentName: newStudent.parentName,
      parentPhone: newStudent.parentPhone,
      parentEmail: newStudent.parentEmail,
      currentSurah: newStudent.currentSurah,
      currentAyah: Number(newStudent.currentAyah)
    });
    setIsAdding(false);
    // Reset form
    setNewStudent({
      name: '',
      grade: 0,
      behaviorScore: 10,
      interests: '',
      birthDate: '',
      age: 0,
      phone: '',
      email: '',
      password: '',
      notes: '',
      parentName: '',
      parentPhone: '',
      parentEmail: '',
      currentSurah: '',
      currentAyah: 1
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Student Directory</h2>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition flex items-center gap-2"
        >
          <User size={18} />
          Add Student
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {students.map((student) => {
          const progress = getProgress(student.currentSurah);

          return (
            <div 
              key={student.id} 
              onClick={() => onSelect(student)}
              className="bg-white p-5 rounded-xl shadow-sm border border-gray-200 hover:shadow-md transition cursor-pointer relative group"
            >
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-lg">
                    {student.name.charAt(0)}
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-800 group-hover:text-indigo-600 transition-colors">{student.name}</h3>
                    <p className="text-xs text-gray-500">ID: {student.id}</p>
                  </div>
                </div>
                <button 
                  onClick={(e) => handleDeleteClick(e, student.id)}
                  className="text-gray-400 hover:text-red-500 transition"
                >
                  <Trash2 size={18} />
                </button>
              </div>

              {/* Progress Bar Section */}
              <div className="mt-5 mb-4">
                <div className="flex justify-between items-center mb-1.5">
                  <span className="text-xs font-semibold text-gray-700 flex items-center gap-1.5">
                    <BookOpen size={14} className="text-indigo-600"/> Quran Progress
                  </span>
                  <span className="text-xs font-bold text-indigo-600">{progress}%</span>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-2.5 mb-2 overflow-hidden">
                  <div className="bg-indigo-600 h-2.5 rounded-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
                </div>
                <div className="flex justify-between items-center bg-gray-50 px-2 py-1.5 rounded border border-gray-100">
                   <div className="flex flex-col">
                      <span className="text-[10px] text-gray-400 uppercase font-bold">Surah</span>
                      <span className="text-xs font-semibold text-gray-700 truncate max-w-[100px]">{student.currentSurah || '-'}</span>
                   </div>
                   <div className="flex flex-col text-right">
                      <span className="text-[10px] text-gray-400 uppercase font-bold">Ayah</span>
                      <span className="text-xs font-semibold text-gray-700">{student.currentAyah || '-'}</span>
                   </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 text-sm">
                <div className="bg-gray-50 p-2 rounded flex flex-col">
                  <span className="text-gray-500 text-xs flex items-center gap-1"><TrendingUp size={12}/> Grade</span>
                  <span className={`font-semibold ${student.grade >= 90 ? 'text-green-600' : student.grade >= 70 ? 'text-yellow-600' : 'text-red-600'}`}>
                    {student.grade}%
                  </span>
                </div>
                <div className="bg-gray-50 p-2 rounded flex flex-col">
                  <span className="text-gray-500 text-xs flex items-center gap-1"><Star size={12}/> Behavior</span>
                  <span className="font-semibold text-gray-800">{student.behaviorScore}/10</span>
                </div>
              </div>

              <div className="mt-3">
                <p className="text-xs text-gray-500 mb-1">Interests</p>
                <div className="flex flex-wrap gap-1 mb-3">
                  {student.interests.map((interest, idx) => (
                    <span key={idx} className="text-xs bg-blue-50 text-blue-700 px-2 py-0.5 rounded-full">
                      {interest}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Confirmation Modal */}
      {studentToDelete && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6 animate-[fadeIn_0.2s_ease-out]">
             <div className="flex items-center gap-3 text-red-600 mb-4">
               <div className="bg-red-100 p-2 rounded-full">
                 <AlertTriangle size={24} />
               </div>
               <h3 className="text-xl font-bold">Delete Student?</h3>
             </div>
             <p className="text-gray-600 mb-6">
               Are you sure you want to delete this student? This action cannot be undone and will remove them from any assigned groups.
             </p>
             <div className="flex justify-end gap-3">
               <button
                 onClick={() => setStudentToDelete(null)}
                 className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
               >
                 Cancel
               </button>
               <button
                 onClick={confirmDelete}
                 className="px-4 py-2 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 transition shadow-sm"
               >
                 Delete Student
               </button>
             </div>
          </div>
        </div>
      )}

      {/* Add Student Modal */}
      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full p-6 animate-[fadeIn_0.2s_ease-out] overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">Add New Student</h3>
              <button onClick={() => setIsAdding(false)} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">

              {/* Personal Information */}
              <div className="bg-gray-50 p-4 rounded-lg border border-gray-100">
                <h4 className="font-semibold text-gray-700 mb-3 flex items-center gap-2">
                  <User size={16} className="text-indigo-600"/> Personal Information
                </h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                    <input
                      required
                      type="text"
                      value={newStudent.name}
                      onChange={e => setNewStudent({...newStudent, name: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="e.g. John Doe"
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium text-gray-700 mb-1">Current Surah</label>
                      <div className="relative">
                        <BookOpen className="absolute left-3 top-2.5 text-gray-400" size={18} />
                        <select
                          value={newStudent.currentSurah}
                          onChange={e => setNewStudent({...newStudent, currentSurah: e.target.value})}
                          className="w-full pl-10 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                        >
                          <option value="">-- Select Surah --</option>
                          {QURAN_SURAHS.map(surah => (
                            <option key={surah} value={surah}>{surah}</option>
                          ))}
                        </select>
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Ayah No.</label>
                      <input
                        type="number"
                        min="1"
                        value={newStudent.currentAyah}
                        onChange={e => setNewStudent({...newStudent, currentAyah: Number(e.target.value)})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="1"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Birth Date</label>
                      <input
                        type="date"
                        value={newStudent.birthDate}
                        onChange={handleDateChange}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Age (Auto-calculated)</label>
                      <input
                        type="number"
                        readOnly
                        value={newStudent.age}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 bg-gray-100 text-gray-500 cursor-not-allowed outline-none"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                      <input
                        type="email"
                        value={newStudent.email}
                        onChange={e => setNewStudent({...newStudent, email: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="student@example.com"
                      />
                    </div>
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                      <input
                        type="password"
                        value={newStudent.password}
                        onChange={e => setNewStudent({...newStudent, password: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="Set password"
                      />
                    </div>
                  </div>

                  <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                      <input
                        type="tel"
                        value={newStudent.phone}
                        onChange={e => setNewStudent({...newStudent, phone: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="(555) 123-4567"
                      />
                  </div>

                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Note</label>
                      <textarea
                        value={newStudent.notes}
                        onChange={e => setNewStudent({...newStudent, notes: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        placeholder="Any additional information..."
                        rows={2}
                      />
                  </div>
                </div>
              </div>

              {/* Parent Section */}
              <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100">
                <h4 className="font-semibold text-indigo-900 mb-3 flex items-center gap-2">
                  <UserCheck size={16} className="text-indigo-600"/> Parent / Guardian Information
                </h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Parent Name</label>
                    <input
                      type="text"
                      value={newStudent.parentName}
                      onChange={e => setNewStudent({...newStudent, parentName: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="e.g. Jane Doe"
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Email</label>
                      <input
                        type="email"
                        value={newStudent.parentEmail}
                        onChange={e => setNewStudent({...newStudent, parentEmail: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Parent Phone</label>
                      <input
                        type="tel"
                        value={newStudent.parentPhone}
                        onChange={e => setNewStudent({...newStudent, parentPhone: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-100">
                <button
                  type="button"
                  onClick={() => setIsAdding(false)}
                  className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm"
                >
                  Save Student
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Student, Group, CalendarEvent } from '../types';
import { ArrowLeft, Mail, Phone, Calendar, Users, UserCog, Lock, Save, Check, User, TrendingUp, Star, UserCheck, BookOpen, Clock, Plus, X, LogOut } from 'lucide-react';
import { QURAN_SURAHS } from '../constants';

interface StudentDetailsProps {
  student: Student;
  groups: Group[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdate: (student: Student) => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'groups' | 'schedule' | 'settings';

export const StudentDetails: React.FC<StudentDetailsProps> = ({ student, groups, events, onBack, onUpdate, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isEnrolling, setIsEnrolling] = useState(false);
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const [formData, setFormData] = useState({
    name: student.name,
    email: student.email || '',
    phone: student.phone || '',
    password: student.password || '',
    parentName: student.parentName || '',
    parentPhone: student.parentPhone || '',
    parentEmail: student.parentEmail || '',
    grade: student.grade,
    behaviorScore: student.behaviorScore,
    notes: student.notes || '',
    currentSurah: student.currentSurah || '',
    currentAyah: student.currentAyah || 1
  });
  const [isSaved, setIsSaved] = useState(false);

  // Filter data
  const studentGroups = groups.filter(g => g.studentIds.includes(student.id));
  const availableGroups = groups.filter(g => !g.studentIds.includes(student.id));
  const groupIds = studentGroups.map(g => g.id);
  const studentEvents = events
    .filter(e => e.groupId && groupIds.includes(e.groupId))
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const getProgress = (surah: string | undefined) => {
    if (!surah) return 0;
    const index = QURAN_SURAHS.indexOf(surah);
    return index !== -1 ? Math.round(((index + 1) / 114) * 100) : 0;
  };

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate({
      ...student,
      ...formData,
      // Ensure numeric types
      grade: Number(formData.grade),
      behaviorScore: Number(formData.behaviorScore),
      currentAyah: Number(formData.currentAyah)
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleEnroll = () => {
    if (selectedGroupId) {
      const groupToUpdate = groups.find(g => g.id === selectedGroupId);
      if (groupToUpdate) {
        onUpdateGroup({
          ...groupToUpdate,
          studentIds: [...groupToUpdate.studentIds, student.id]
        });
        setSelectedGroupId('');
        setIsEnrolling(false);
      }
    }
  };

  const handleUnenroll = (group: Group) => {
    if(window.confirm(`Are you sure you want to remove ${student.name} from ${group.name}?`)) {
        onUpdateGroup({
            ...group,
            studentIds: group.studentIds.filter(id => id !== student.id)
        });
    }
  };

  return (
    <div className="space-y-6">
       {/* Header */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
            onClick={onBack} 
            className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
          >
            <ArrowLeft size={18} />
            Back to Directory
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
           <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             {student.name.charAt(0)}
           </div>
           <div>
             <h1 className="text-3xl font-bold text-gray-800">{student.name}</h1>
             <div className="flex flex-wrap gap-4 mt-2 text-gray-600">
               {student.email && <span className="flex items-center gap-1"><Mail size={16} /> {student.email}</span>}
               {student.phone && <span className="flex items-center gap-1"><Phone size={16} /> {student.phone}</span>}
               <span className="flex items-center gap-1"><Calendar size={16} /> Age: {student.age || 'N/A'}</span>
             </div>
           </div>
        </div>
       </div>

       {/* Tabs */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="flex border-b border-gray-200 overflow-x-auto">
             <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Details
          </button>
          <button 
            onClick={() => setActiveTab('groups')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'groups' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Groups
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'schedule' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Schedule
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'settings' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            Settings
          </button>
          </div>

          <div className="p-6 min-h-[300px]">
             {activeTab === 'details' && (
                 <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                             <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <TrendingUp size={18} className="text-indigo-500"/> Performance & Progress
                             </h3>
                             <div className="space-y-4">

                                {/* New Progress Bar Visualization */}
                                <div className="mb-6 p-4 bg-white rounded-xl border border-indigo-100 shadow-sm">
                                    <div className="flex items-center justify-between mb-2">
                                        <div className="flex items-center gap-2">
                                            <div className="p-1.5 bg-indigo-100 text-indigo-600 rounded-lg">
                                                <BookOpen size={18} />
                                            </div>
                                            <h4 className="font-bold text-gray-800">Quran Memorization</h4>
                                        </div>
                                        <span className="text-lg font-bold text-indigo-600">{getProgress(student.currentSurah)}%</span>
                                    </div>

                                    <div className="w-full bg-gray-100 rounded-full h-3 mb-3">
                                        <div className="bg-indigo-600 h-3 rounded-full transition-all duration-1000" style={{ width: `${getProgress(student.currentSurah)}%` }}></div>
                                    </div>

                                    <div className="flex items-center justify-between bg-gray-50 p-3 rounded-lg border border-gray-100">
                                        <div>
                                            <span className="block text-xs text-gray-500 uppercase font-semibold">Current Surah</span>
                                            <span className="font-bold text-gray-800">{student.currentSurah || 'Not started'}</span>
                                        </div>
                                        <div className="text-right">
                                            <span className="block text-xs text-gray-500 uppercase font-semibold">Current Ayah</span>
                                            <span className="font-bold text-gray-800">{student.currentAyah || '-'}</span>
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Grade</span>
                                        <span className="font-bold">{student.grade}%</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-indigo-600 h-2 rounded-full" style={{width: `${student.grade}%`}}></div>
                                    </div>
                                </div>
                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">Behavior Score</span>
                                        <span className="font-bold">{student.behaviorScore}/10</span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-2">
                                        <div className="bg-green-500 h-2 rounded-full" style={{width: `${student.behaviorScore * 10}%`}}></div>
                                    </div>
                                </div>
                             </div>
                        </div>

                        <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                            <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
                                <UserCheck size={18} className="text-indigo-500"/> Parent/Guardian
                             </h3>
                             <ul className="space-y-3 text-sm">
                                <li className="flex gap-2">
                                    <User size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Name:</span>
                                    <span className="font-medium text-gray-800">{student.parentName || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Phone size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Phone:</span>
                                    <span className="font-medium text-gray-800">{student.parentPhone || 'N/A'}</span>
                                </li>
                                <li className="flex gap-2">
                                    <Mail size={16} className="text-gray-400" />
                                    <span className="text-gray-600">Email:</span>
                                    <span className="font-medium text-gray-800">{student.parentEmail || 'N/A'}</span>
                                </li>
                             </ul>
                        </div>
                    </div>

                    <div className="p-4 bg-yellow-50 rounded-lg border border-yellow-100">
                        <h3 className="font-semibold text-gray-800 mb-2">Notes</h3>
                        <p className="text-sm text-gray-700">{student.notes || 'No additional notes.'}</p>
                    </div>
                 </div>
             )}

             {activeTab === 'groups' && (
                 <div className="space-y-4">
                  <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-800">Enrolled Groups</h3>
                    <button 
                        onClick={() => setIsEnrolling(!isEnrolling)}
                        className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition ${isEnrolling ? 'bg-gray-100 text-gray-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
                    >
                        {isEnrolling ? <X size={16} /> : <Plus size={16} />}
                        {isEnrolling ? 'Cancel' : 'Enroll in Group'}
                    </button>
                  </div>

                  {isEnrolling && (
                    <div className="bg-gray-50 p-4 rounded-xl border border-indigo-100 mb-6 animate-[fadeIn_0.2s_ease-out]">
                        <h4 className="font-semibold text-gray-700 mb-3 text-sm">Select a group to enroll in:</h4>
                        {availableGroups.length === 0 ? (
                            <div className="text-gray-500 italic text-sm">Student is already in all available groups.</div>
                        ) : (
                            <div className="flex flex-col sm:flex-row gap-3">
                                <select
                                    value={selectedGroupId}
                                    onChange={(e) => setSelectedGroupId(e.target.value)}
                                    className="flex-1 p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-sm"
                                >
                                    <option value="">-- Select Group --</option>
                                    {availableGroups.map(g => (
                                        <option key={g.id} value={g.id}>{g.name}</option>
                                    ))}
                                </select>
                                <button
                                    onClick={handleEnroll}
                                    disabled={!selectedGroupId}
                                    className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
                                >
                                    Enroll
                                </button>
                            </div>
                        )}
                    </div>
                  )}

                  {studentGroups.length === 0 ? (
                    <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                      <Users size={32} className="mx-auto mb-2 opacity-30" />
                      <p>Student is not enrolled in any groups.</p>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {studentGroups.map(group => (
                             <div key={group.id} className="border border-gray-200 rounded-lg p-4 hover:border-indigo-200 transition bg-white flex justify-between items-start group">
                                <div>
                                    <h4 className="font-bold text-indigo-700 flex items-center gap-2">
                                        <Users size={18} /> {group.name}
                                    </h4>
                                    <p className="text-sm text-gray-600 mt-1">{group.description}</p>
                                </div>
                                <button 
                                    onClick={() => handleUnenroll(group)}
                                    className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                                    title="Leave Group"
                                >
