import { initializeApp } from "firebase/app";
import { getFirestore, Firestore } from "firebase/firestore";

const STORAGE_KEY = 'mosquestrack_firebase_config';

const placeholderConfig = {
  apiKey: "YOUR_API_KEY", 
  authDomain: "YOUR_PROJECT_ID.firebaseapp.com",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_PROJECT_ID.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// 1. Try to get config from LocalStorage
const getStoredConfig = () => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch (e) {
    console.error("Failed to parse stored firebase config", e);
    return null;
  }
};

const configToUse = getStoredConfig() || placeholderConfig;

// 2. Check if valid
const isConfigured = configToUse.apiKey !== "YOUR_API_KEY" && !configToUse.apiKey.includes("YOUR_API_KEY");

let app;
let dbInstance: Firestore | null = null;

if (isConfigured) {
  try {
    app = initializeApp(configToUse);
    dbInstance = getFirestore(app);
    console.log("Firebase initialized successfully");
  } catch (error) {
    console.error("Firebase initialization failed:", error);
  }
} else {
  console.warn("Firebase not configured with valid keys. Using mock in-memory database.");
}

export const db = dbInstance;
export const isLive = !!dbInstance;

// Helpers for the Settings UI
export const saveFirebaseConfig = (config: any) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(config));
  window.location.reload();
};

export const clearFirebaseConfig = () => {
  localStorage.removeItem(STORAGE_KEY);
  window.location.reload();
};

