interface AdminSettingsProps {
  credentials: { name: string; email: string; password: string };
  onUpdate: (creds: { name: string; email: string; password: string }) => void;
}

export const AdminSettings: React.FC<AdminSettingsProps> = ({ credentials, onUpdate }) => {
  const [formData, setFormData] = useState(credentials);
  const [success, setSuccess] = useState(false);

  // Database Config State
  const [configInput, setConfigInput] = useState('');
  const [configError, setConfigError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate(formData);
    setSuccess(true);
    setTimeout(() => setSuccess(false), 3000);
  };

  const handleConnectDb = () => {
    try {
      setConfigError('');
      // Flexible parsing: try to find the JSON object if user pasted full JS code
      let jsonStr = configInput;

      // If user pasted "const firebaseConfig = { ... };", extract the object
      if (jsonStr.includes('=')) {
         const match = jsonStr.match(/{[\s\S]*}/);
         if (match) {
             jsonStr = match[0];
         }
      }

      // Allow loose JSON (keys without quotes) by using a rigorous regex or simple eval (risky but acceptable for admin client-side tool)
      // Safest way for this context: Try standard JSON.parse first, then warn.
      // We'll ask user to ensure it's valid JSON

      // Basic cleanup of trailing commas which might break JSON.parse
      jsonStr = jsonStr.replace(/,(\s*[}\]])/g, '$1');

      // Attempt to parse strictly first
      let configObj;
      try {
        configObj = JSON.parse(jsonStr);
      } catch (e) {
        // If standard JSON fails, we might need to tell user to format it as JSON
        // Or we can try to be helpful if they pasted JS object keys without quotes
        throw new Error("Invalid JSON format. Please ensure keys are quoted (e.g. \"apiKey\": \"...\")");
      }

      if (!configObj.apiKey || !configObj.projectId) {
        throw new Error("Config object missing required fields (apiKey, projectId)");
      }

      saveFirebaseConfig(configObj);
    } catch (e: any) {
      setConfigError(e.message || "Failed to parse configuration");
    }
