              )}
           </div>
        </form>
      </div>

      {/* Database Connection */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 max-w-3xl">
         <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
