            <GroupDetails
              group={selectedGroup}
              students={students}
              teachers={teachers}
              events={events}
              onBack={() => setSelectedGroupId(null)}
              onUpdateGroup={handleUpdateGroup}
            />
          );
        }

        // Wrapper for Group Manager to handle DB ops via props
        const setGroupsWrapper = (action: any) => {
            // Placeholder: GroupManager logic is partly inside the component
            // We pass updated methods below
        };

        return (
          <GroupManager 
            students={students} 
            teachers={teachers}
            groups={groups} 
            setGroups={setGroupsWrapper as any} 
            onSelect={handleGroupSelect}
            onAddGroup={(g: Group) => dbService.addGroup(g)}
            onDeleteGroup={(id: string) => dbService.deleteGroup(id)}
          />
        );
      case 'scheduler':
        return (
            <Scheduler 
                groups={groups} 
                events={events} 
                setEvents={handleSetEvents as any} 
                onAddEvent={(e: CalendarEvent) => dbService.addEvent(e)}
            />
        );
      case 'settings':
        return (
          <AdminSettings 
            credentials={adminCredentials} 
            onUpdate={(newCreds) => {
              setAdminCredentials(newCreds);
              setCurrentUser(prev => prev ? ({...prev, name: newCreds.name, email: newCreds.email}) : null);
            }} 
          />
        );
      case 'dashboard':
      default:
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-gray-800">Dashboard Overview</h2>
                {/* Seed button only shows if DB is active, but we can allow mock reseeding too */}
                {students.length === 0 && teachers.length === 0 && (
