                    </div>
                  ) : (
                    <p className="text-gray-500 text-sm">Everyone is doing great! No immediate alerts.</p>
                  )}
               </div>
            </div>
          </div>
        );
    }
  };

  // --- Auth Guard ---
  if (!currentUser) {
    return <Login students={students} teachers={teachers} adminCredentials={adminCredentials} onLogin={handleLogin} />;
