                                     <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Parent Portal Password</label>
                                        <div className="relative">
                                            <Lock size={16} className="absolute left-3 top-2.5 text-gray-400" />
                                            <input
                                                type="password"
                                                value={formData.parentPassword}
                                                onChange={e => setFormData({...formData, parentPassword: e.target.value})}
                                                className="w-full pl-9 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                                                placeholder="Reset parent password"
                                            />
                                        </div>
                                     </div>
                                 </div>
                             </div>

                             <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                                <textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500" />
                             </div>
                        </div>

                        <div className="flex items-center gap-4">
