        >
          <User size={18} />
          إضافة طالب
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {students.map((student) => {
          const progress = getProgress(student.currentSurah);

          return (
            <div 
              key={student.id} 
