import React, { useState } from 'react';
import { Student, Group, Teacher } from '../types';
import { Users, X, ChevronLeft, Plus, User } from 'lucide-react';

interface GroupManagerProps {
  students: Student[];
  teachers: Teacher[];
  groups: Group[];
  setGroups: React.Dispatch<React.SetStateAction<Group[]>>;
  onSelect: (group: Group) => void;
  onAddGroup?: (group: Group) => void;
  onDeleteGroup?: (id: string) => void;
}

export const GroupManager: React.FC<GroupManagerProps> = ({ students, teachers, groups, setGroups, onSelect, onAddGroup, onDeleteGroup }) => {
  const [newGroupName, setNewGroupName] = useState('');
  const [newGroupDesc, setNewGroupDesc] = useState('');
  const [newGroupTeacherId, setNewGroupTeacherId] = useState('');

  const handleCreateGroup = () => {
    if (!newGroupName.trim() || !newGroupTeacherId) return;
    const newGroup: Group = {
      id: crypto.randomUUID(),
      name: newGroupName,
      description: newGroupDesc || 'لا يوجد وصف',
      studentIds: [],
      teacherId: newGroupTeacherId
    };

    if (onAddGroup) {
      onAddGroup(newGroup);
    } else {
      setGroups(prev => [...prev, newGroup]);
    }

    setNewGroupName('');
    setNewGroupDesc('');
    setNewGroupTeacherId('');
  };

  const deleteGroup = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("هل أنت متأكد من حذف هذه الحلقة؟")) {
      if (onDeleteGroup) {
        onDeleteGroup(id);
      } else {
        setGroups(prev => prev.filter(g => g.id !== id));
      }
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800">إدارة الحلقات</h2>
      </div>

      {/* Manual Creation Panel */}
      <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
        <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Plus size={20} className="text-indigo-600"/>
          إنشاء حلقة جديدة
        </h3>
        <div className="flex flex-col md:flex-row gap-4 items-end">
          <div className="flex-1 w-full">
            <label className="block text-xs font-medium text-gray-500 mb-1">اسم الحلقة</label>
            <input
              type="text"
              value={newGroupName}
              onChange={(e) => setNewGroupName(e.target.value)}
              placeholder="مثال: حلقة المتميزين"
              className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
          <div className="flex-1 w-full">
            <label className="block text-xs font-medium text-gray-500 mb-1">المعلم المسؤول</label>
            <select
                value={newGroupTeacherId}
                onChange={(e) => setNewGroupTeacherId(e.target.value)}
                className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
            >
                <option value="">-- اختر المعلم --</option>
                {teachers.map(t => (
                    <option key={t.id} value={t.id}>{t.name}</option>
                ))}
            </select>
          </div>
          <div className="flex-[2] w-full">
            <label className="block text-xs font-medium text-gray-500 mb-1">الوصف</label>
            <input
              type="text"
              value={newGroupDesc}
              onChange={(e) => setNewGroupDesc(e.target.value)}
              placeholder="وصف الحلقة (اختياري)"
              className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
          <button
            onClick={handleCreateGroup}
            disabled={!newGroupName || !newGroupTeacherId}
            className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition flex items-center gap-2 justify-center h-[42px]"
          >
            إنشاء
          </button>
        </div>
        {!newGroupTeacherId && newGroupName && (
            <p className="text-xs text-red-500 mt-2 flex items-center gap-1">
                * يرجى تعيين معلم لإنشاء الحلقة.
            </p>
        )}
      </div>

      {/* Group Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {groups.map((group) => {
            const groupTeacher = teachers.find(t => t.id === group.teacherId);
            return (
              <div 
                key={group.id} 
                onClick={() => onSelect(group)}
                className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden cursor-pointer hover:shadow-md transition group"
              >
                <div className="p-4 border-b border-gray-100 bg-gray-50 flex justify-between items-start">
                  <div>
                    <h3 className="font-bold text-gray-800 flex items-center gap-2 group-hover:text-indigo-600 transition-colors">
                      <Users size={18} className="text-indigo-500" />
                      {group.name}
                    </h3>
                    <p className="text-xs text-gray-500 mt-1">{group.description}</p>
                    {groupTeacher && (
                        <p className="text-xs text-indigo-600 mt-2 flex items-center gap-1 font-medium bg-indigo-50 w-fit px-2 py-0.5 rounded">
                            <User size={12} /> {groupTeacher.name}
                        </p>
                    )}
                    {!groupTeacher && (
                         <p className="text-xs text-red-500 mt-2 flex items-center gap-1 font-medium bg-red-50 w-fit px-2 py-0.5 rounded">
                            <User size={12} /> لم يتم تعيين معلم
                         </p>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={(e) => deleteGroup(e, group.id)} 
                      className="text-gray-400 hover:text-red-500 p-1 hover:bg-red-50 rounded"
                    >
                      <X size={18} />
                    </button>
                    <ChevronLeft size={18} className="text-gray-300" />
                  </div>
                </div>
                <div className="p-4">
                  <div className="flex flex-wrap gap-2">
                    {group.studentIds.map(sid => {
                      const student = students.find(s => s.id === sid);
                      return student ? (
                        <div key={sid} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-full text-sm">
                          <span className="w-2 h-2 rounded-full bg-indigo-400"></span>
                          {student.name}
                        </div>
                      ) : null;
                    })}
                  </div>
                  {group.studentIds.length === 0 && (
                    <p className="text-gray-400 text-sm italic">لا يوجد طلاب مسجلين.</p>
                  )}
                </div>
              </div>
            );
        })}

        {groups.length === 0 && (
          <div className="col-span-full text-center py-12 text-gray-400 bg-white rounded-xl border border-dashed border-gray-300">
            <Users size={48} className="mx-auto mb-3 opacity-20" />
            <p>لا توجد حلقات مضافة بعد. أنشئ واحدة يدوياً.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Group, CalendarEvent } from '../types';
import { Calendar as CalendarIcon, Clock, Plus, X } from 'lucide-react';

interface SchedulerProps {
  groups: Group[];
  events: CalendarEvent[];
  setEvents: React.Dispatch<React.SetStateAction<CalendarEvent[]>>;
  onAddEvent?: (event: CalendarEvent) => void;
}

export const Scheduler: React.FC<SchedulerProps> = ({ groups, events, setEvents, onAddEvent }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newEvent, setNewEvent] = useState<Partial<CalendarEvent>>({
    title: '',
    startTime: '',
    durationMinutes: 60,
    type: 'class',
    description: ''
  });

  const handleAddEvent = (e: React.FormEvent) => {
    e.preventDefault();
    if (newEvent.title && newEvent.startTime) {
       const eventObj: CalendarEvent = {
         id: crypto.randomUUID(),
         title: newEvent.title!,
         startTime: newEvent.startTime!,
         durationMinutes: newEvent.durationMinutes || 60,
         type: newEvent.type as any || 'class',
         description: newEvent.description,
         groupId: newEvent.groupId
       };

       if (onAddEvent) {
         onAddEvent(eventObj);
       } else {
         setEvents(prev => [...prev, eventObj]);
       }

       setIsAdding(false);
       setNewEvent({ title: '', startTime: '', durationMinutes: 60, type: 'class', description: '' });
    }
  };

  const getEventColor = (type: CalendarEvent['type']) => {
    switch (type) {
      case 'class': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'meeting': return 'bg-purple-100 text-purple-700 border-purple-200';
      case 'activity': return 'bg-green-100 text-green-700 border-green-200';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const sortedEvents = [...events].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">الجدول الأسبوعي</h2>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex items-center justify-between mb-6">
          <h3 className="font-semibold text-lg text-gray-700 flex items-center gap-2">
            <CalendarIcon size={20} />
            الأحداث القادمة
          </h3>
          <button 
            onClick={() => setIsAdding(true)}
            className="text-sm text-indigo-600 font-medium hover:underline flex items-center gap-1"
          >
            <Plus size={16} /> إضافة حدث يدوياً
          </button>
        </div>

        <div className="space-y-4">
          {sortedEvents.length === 0 ? (
             <p className="text-center text-gray-400 py-10 italic">لا توجد أحداث قادمة.</p>
          ) : (
            sortedEvents.map(event => {
              const date = new Date(event.startTime);
              const group = groups.find(g => g.id === event.groupId);

              return (
                <div key={event.id} className={`p-4 rounded-lg border-r-4 ${getEventColor(event.type)} bg-opacity-30 border-opacity-50 flex flex-col md:flex-row md:items-center justify-between gap-4`}>
                  <div className="flex items-start gap-4">
                    <div className="bg-white bg-opacity-60 rounded-lg p-2 text-center min-w-[60px]">
                      <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('ar-EG', { month: 'short' })}</span>
                      <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-800">{event.title}</h4>
                      <div className="flex items-center gap-3 text-sm text-gray-600 mt-1">
                        <span className="flex items-center gap-1"><Clock size={14} /> {date.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })} ({event.durationMinutes} دقيقة)</span>
                        {group && <span className="px-2 py-0.5 bg-gray-200 rounded text-xs">{group.name}</span>}
                      </div>
                      {event.description && <p className="text-sm text-gray-500 mt-2">{event.description}</p>}
                    </div>
                  </div>
                  <span className={`text-xs font-bold px-2 py-1 rounded uppercase tracking-wide self-start md:self-center ${getEventColor(event.type).split(' ')[1]}`}>
                    {event.type === 'class' ? 'درس' : event.type === 'meeting' ? 'اجتماع' : 'نشاط'}
                  </span>
                </div>
              );
            })
          )}
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-gray-800">إضافة حدث</h3>
              <button onClick={() => setIsAdding(false)} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleAddEvent} className="space-y-4">
               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">عنوان الحدث</label>
                  <input
                    required
                    type="text"
                    value={newEvent.title}
                    onChange={e => setNewEvent({...newEvent, title: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">وقت البدء</label>
                    <input
                      required
                      type="datetime-local"
                      value={newEvent.startTime}
                      onChange={e => setNewEvent({...newEvent, startTime: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">المدة (دقيقة)</label>
                    <input
                      required
                      type="number"
                      value={newEvent.durationMinutes}
                      onChange={e => setNewEvent({...newEvent, durationMinutes: Number(e.target.value)})}
                      className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">النوع</label>
                      <select
                        value={newEvent.type}
                        onChange={e => setNewEvent({...newEvent, type: e.target.value as any})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      >
                        <option value="class">درس</option>
                        <option value="meeting">اجتماع</option>
                        <option value="activity">نشاط</option>
                      </select>
                   </div>
                   <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">الحلقة (اختياري)</label>
                      <select
                        value={newEvent.groupId || ''}
                        onChange={e => setNewEvent({...newEvent, groupId: e.target.value})}
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      >
                        <option value="">لا يوجد</option>
                        {groups.map(g => (
                          <option key={g.id} value={g.id}>{g.name}</option>
                        ))}
                      </select>
                   </div>
               </div>
               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">الوصف</label>
                  <textarea
                    value={newEvent.description}
                    onChange={e => setNewEvent({...newEvent, description: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    rows={2}
                  />
               </div>
               <div className="flex justify-end gap-3 pt-2">
                 <button type="button" onClick={() => setIsAdding(false)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg">إلغاء</button>
                 <button type="submit" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">حفظ الحدث</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Student, Group, CalendarEvent } from '../types';
import { ArrowRight, Mail, Phone, Calendar, Users, UserCog, Lock, Save, Check, User, TrendingUp, Star, UserCheck, BookOpen, Clock, Plus, X, LogOut } from 'lucide-react';
import { QURAN_SURAHS } from '../constants';

interface StudentDetailsProps {
  student: Student;
  groups: Group[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdate: (student: Student) => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'groups' | 'schedule' | 'settings';

export const StudentDetails: React.FC<StudentDetailsProps> = ({ student, groups, events, onBack, onUpdate, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isEnrolling, setIsEnrolling] = useState(false);
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const [formData, setFormData] = useState({
    name: student.name,
    email: student.email || '',
    phone: student.phone || '',
    password: student.password || '',
    parentName: student.parentName || '',
    parentPhone: student.parentPhone || '',
    parentEmail: student.parentEmail || '',
    parentPassword: student.parentPassword || '',
    grade: student.grade,
    behaviorScore: student.behaviorScore,
    notes: student.notes || '',
    currentSurah: student.currentSurah || '',
    currentAyah: student.currentAyah || 1
  });
  const [isSaved, setIsSaved] = useState(false);

  // Filter data
  const studentGroups = groups.filter(g => g.studentIds.includes(student.id));
  const availableGroups = groups.filter(g => !g.studentIds.includes(student.id));
  const groupIds = studentGroups.map(g => g.id);
  const studentEvents = events
    .filter(e => e.groupId && groupIds.includes(e.groupId))
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const getProgress = (surah: string | undefined) => {
    if (!surah) return 0;
    const index = QURAN_SURAHS.indexOf(surah);
    return index !== -1 ? Math.round(((index + 1) / 114) * 100) : 0;
  };

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate({
      ...student,
      ...formData,
      grade: Number(formData.grade),
      behaviorScore: Number(formData.behaviorScore),
      currentAyah: Number(formData.currentAyah)
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleEnroll = () => {
    if (selectedGroupId) {
      const groupToUpdate = groups.find(g => g.id === selectedGroupId);
      if (groupToUpdate) {
        onUpdateGroup({
          ...groupToUpdate,
          studentIds: [...groupToUpdate.studentIds, student.id]
        });
        setSelectedGroupId('');
        setIsEnrolling(false);
      }
    }
  };

  const handleUnenroll = (group: Group) => {
    if(window.confirm(`هل أنت متأكد من إزالة ${student.name} من ${group.name}؟`)) {
        onUpdateGroup({
            ...group,
            studentIds: group.studentIds.filter(id => id !== student.id)
        });
    }
  };

  return (
    <div className="space-y-6">
       {/* Header */}
       <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
            onClick={onBack} 
            className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
          >
            <ArrowRight size={18} />
            العودة للدليل
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
           <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             {student.name.charAt(0)}
           </div>
           <div>
             <h1 className="text-3xl font-bold text-gray-800">{student.name}</h1>
