                                            <span className="font-bold text-gray-800">{student.currentAyah || '-'}</span>
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <div className="flex justify-between text-sm mb-1">
                                        <span className="text-gray-600">الدرجة</span>
