import React, { useState } from 'react';
import { Teacher, Group, CalendarEvent, Student } from '../types';
import { ArrowRight, Mail, BookOpen, Clock, Calendar, Users, Briefcase, UserCog, Lock, Save, Check, User } from 'lucide-react';

interface TeacherDetailsProps {
  teacher: Teacher;
  groups: Group[];
  events: CalendarEvent[];
  students: Student[];
  onBack: () => void;
  onUpdate: (teacher: Teacher) => void;
  standalone?: boolean;
}

type TabType = 'details' | 'groups' | 'seance' | 'settings';

export const TeacherDetails: React.FC<TeacherDetailsProps> = ({ teacher, groups, events, students, onBack, onUpdate, standalone = false }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [formData, setFormData] = useState({
    name: teacher.name,
    email: teacher.email,
    subject: teacher.subject,
    password: teacher.password || '',
  });
  const [isSaved, setIsSaved] = useState(false);

  // Filter data for this teacher
  const teacherGroups = groups.filter(g => g.teacherId === teacher.id);
  const teacherEvents = events.filter(e => e.teacherId === teacher.id).sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate({
      ...teacher,
      name: formData.name,
      email: formData.email,
      subject: formData.subject,
      password: formData.password,
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        {!standalone && (
          <button 
            onClick={onBack} 
            className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
          >
            <ArrowRight size={18} />
            العودة للدليل
          </button>
        )}

        <div className="flex flex-col md:flex-row gap-6 items-start">
          <div className="w-20 h-20 bg-purple-100 rounded-full flex items-center justify-center text-purple-600 font-bold text-3xl shrink-0">
             {teacher.name.charAt(0)}
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-800">{teacher.name}</h1>
            <p className="text-lg text-indigo-600 font-medium">{teacher.subject}</p>
            <div className="flex items-center gap-4 mt-2 text-gray-600">
              <span className="flex items-center gap-1"><Mail size={16} /> {teacher.email}</span>
              <span className="flex items-center gap-1"><Briefcase size={16} /> خبرة {teacher.yearsExperience} سنوات</span>
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="flex border-b border-gray-200 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            التفاصيل
          </button>
          <button 
            onClick={() => setActiveTab('groups')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'groups' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            الحلقات
          </button>
          <button 
            onClick={() => setActiveTab('seance')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'seance' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            الحصص
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-4 px-4 text-center font-medium transition whitespace-nowrap ${activeTab === 'settings' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            الإعدادات
          </button>
        </div>

        <div className="p-6 min-h-[300px]">
          {/* Details Tab */}
          {activeTab === 'details' && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                  <h3 className="font-semibold text-gray-800 mb-2 flex items-center gap-2">
                    <BookOpen size={18} className="text-indigo-500"/> إحصائيات التدريس
                  </h3>
                  <ul className="space-y-2 text-sm text-gray-600">
                    <li className="flex justify-between"><span>عدد الحلقات:</span> <span className="font-medium">{teacherGroups.length}</span></li>
                    <li className="flex justify-between"><span>الحصص الأسبوعية:</span> <span className="font-medium">{teacherEvents.length}</span></li>
                    <li className="flex justify-between"><span>المادة:</span> <span className="font-medium">{teacher.subject}</span></li>
                  </ul>
                </div>
                <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                  <h3 className="font-semibold text-gray-800 mb-2 flex items-center gap-2">
                    <Clock size={18} className="text-indigo-500"/> أوقات العمل
                  </h3>
                  <p className="text-sm text-gray-600">ساعات العمل الرسمية: 8:00 صباحاً - 4:00 عصراً</p>
                  <p className="text-sm text-gray-600 mt-2 italic">تواصل عبر البريد للمواعيد الخاصة.</p>
                </div>
              </div>
            </div>
          )}

          {/* Groups Tab */}
          {activeTab === 'groups' && (
            <div className="space-y-4">
              <h3 className="font-bold text-gray-800 mb-4">الحلقات المسندة</h3>
              {teacherGroups.length === 0 ? (
                <p className="text-gray-400 italic">لا توجد حلقات مسندة لهذا المعلم.</p>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {teacherGroups.map(group => (
                    <div key={group.id} className="border border-gray-200 rounded-lg p-4 hover:border-indigo-200 transition">
                      <h4 className="font-bold text-indigo-700 flex items-center gap-2">
                        <Users size={18} /> {group.name}
                      </h4>
                      <p className="text-sm text-gray-600 mt-1">{group.description}</p>
                      <div className="mt-3 flex items-center gap-2 text-xs text-gray-500">
                        <span className="bg-gray-100 px-2 py-1 rounded-full">{group.studentIds.length} طلاب</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Seance / Sessions Tab */}
          {activeTab === 'seance' && (
            <div className="space-y-4">
               <h3 className="font-bold text-gray-800 mb-4">الحصص القادمة</h3>
               {teacherEvents.length === 0 ? (
                 <p className="text-gray-400 italic">لا توجد حصص مجدولة.</p>
               ) : (
                 <div className="space-y-3">
                   {teacherEvents.map(event => {
                     const date = new Date(event.startTime);
                     const group = groups.find(g => g.id === event.groupId);
                     return (
                      <div key={event.id} className="flex items-start gap-4 p-4 border border-gray-100 rounded-lg bg-gray-50">
                        <div className="flex-shrink-0 w-16 text-center bg-white rounded border border-gray-200 p-2">
                           <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('ar-EG', { weekday: 'short' })}</span>
                           <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                        </div>
                        <div>
                          <h4 className="font-bold text-gray-800">{event.title}</h4>
                          <p className="text-sm text-gray-600 flex items-center gap-2 mt-1">
                            <Clock size={14} /> 
                            {date.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })} - 
                            {new Date(date.getTime() + event.durationMinutes * 60000).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}
                          </p>
                          {group && (
                            <span className="inline-block mt-2 text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded">
                              {group.name}
                            </span>
                          )}
                        </div>
                      </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}

          {/* Settings Tab */}
          {activeTab === 'settings' && (
            <div className="max-w-2xl mx-auto">
               <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
                 <UserCog size={24} className="text-indigo-600" />
                 إعدادات ملف المعلم
               </h3>

               <form onSubmit={handleUpdate} className="space-y-6">
                 <div className="space-y-4 bg-gray-50 p-6 rounded-xl border border-gray-200">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">الاسم المعروض</label>
                      <div className="relative">
                        <User className="absolute right-3 top-2.5 text-gray-400" size={18} />
                        <input
                          type="text"
                          required
                          value={formData.name}
                          onChange={e => setFormData({...formData, name: e.target.value})}
                          className="w-full pr-10 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                      </div>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">التخصص</label>
                      <div className="relative">
                        <BookOpen className="absolute right-3 top-2.5 text-gray-400" size={18} />
                        <input
                          type="text"
                          required
                          value={formData.subject}
                          onChange={e => setFormData({...formData, subject: e.target.value})}
                          className="w-full pr-10 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                      </div>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">البريد الإلكتروني</label>
                      <div className="relative">
                        <Mail className="absolute right-3 top-2.5 text-gray-400" size={18} />
                        <input
                          type="email"
                          readOnly
                          value={formData.email}
                          className="w-full pr-10 border border-gray-300 rounded-lg px-3 py-2 bg-gray-100 text-gray-500 cursor-not-allowed outline-none"
                        />
                      </div>
                      <p className="text-xs text-gray-500 mt-1">لا يمكن تغيير البريد الإلكتروني.</p>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">كلمة المرور</label>
                      <div className="relative">
                        <Lock className="absolute right-3 top-2.5 text-gray-400" size={18} />
                        <input
                          type="text" 
                          required
                          value={formData.password}
                          onChange={e => setFormData({...formData, password: e.target.value})}
                          className="w-full pr-10 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                      </div>
                    </div>
                 </div>

                 <div className="flex items-center gap-4">
                   <button
                     type="submit"
                     className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm flex items-center gap-2"
                   >
                     <Save size={18} />
                     حفظ التغييرات
                   </button>
                   {isSaved && (
                     <span className="text-green-600 flex items-center gap-1.5 text-sm font-medium animate-[fadeIn_0.3s_ease-out]">
                       <Check size={18} />
                       تم تحديث الملف!
                     </span>
                   )}
                 </div>
               </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Group, Student, Teacher, CalendarEvent } from '../types';
import { ArrowRight, Users, Calendar, BookOpen, User, Clock, CheckCircle2, Plus, X, Pencil, Check } from 'lucide-react';

interface GroupDetailsProps {
  group: Group;
  students: Student[];
  teachers: Teacher[];
  events: CalendarEvent[];
  onBack: () => void;
  onUpdateGroup: (group: Group) => void;
}

type TabType = 'details' | 'student' | 'scheduler';

export const GroupDetails: React.FC<GroupDetailsProps> = ({ group, students, teachers, events, onBack, onUpdateGroup }) => {
  const [activeTab, setActiveTab] = useState<TabType>('details');
  const [isAddingStudent, setIsAddingStudent] = useState(false);
  const [selectedStudentId, setSelectedStudentId] = useState('');

  const [isEditingTeacher, setIsEditingTeacher] = useState(false);
  const [selectedTeacherId, setSelectedTeacherId] = useState(group.teacherId || '');

  const groupStudents = students.filter(s => group.studentIds.includes(s.id));
  const groupTeacher = teachers.find(t => t.id === group.teacherId);
  const groupEvents = events
    .filter(e => e.groupId === group.id)
    .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

  const availableStudents = students.filter(s => !group.studentIds.includes(s.id));

  const handleAddStudent = () => {
    if (selectedStudentId) {
      const updatedGroup = {
        ...group,
        studentIds: [...group.studentIds, selectedStudentId]
      };
      onUpdateGroup(updatedGroup);
      setSelectedStudentId('');
      setIsAddingStudent(false);
    }
  };

  const handleSaveTeacher = () => {
      onUpdateGroup({
          ...group,
          teacherId: selectedTeacherId
      });
      setIsEditingTeacher(false);
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <button 
          onClick={onBack} 
          className="flex items-center gap-2 text-gray-500 hover:text-indigo-600 mb-4 transition"
        >
          <ArrowRight size={18} />
          العودة للحلقات
        </button>

        <div className="flex flex-col md:flex-row gap-6 items-start">
          <div className="w-20 h-20 bg-indigo-100 rounded-xl flex items-center justify-center text-indigo-600 font-bold text-3xl shrink-0">
             <Users size={40} />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-800">{group.name}</h1>
            <p className="text-lg text-gray-600 mt-1">{group.description}</p>
            <div className="flex items-center gap-4 mt-3 text-sm text-gray-500">
              <span className="flex items-center gap-1"><Users size={16} /> {groupStudents.length} طلاب</span>
              {groupTeacher ? (
                <span className="flex items-center gap-1 bg-purple-50 text-purple-700 px-2 py-0.5 rounded-full border border-purple-100">
                  <User size={14} /> المعلم: {groupTeacher.name}
                </span>
              ) : (
                <span className="flex items-center gap-1 bg-red-50 text-red-700 px-2 py-0.5 rounded-full border border-red-100">
                  <User size={14} /> لم يتم تعيين معلم
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="flex border-b border-gray-200">
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'details' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            التفاصيل
          </button>
          <button 
            onClick={() => setActiveTab('student')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'student' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            الطلاب
          </button>
          <button 
            onClick={() => setActiveTab('scheduler')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'scheduler' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'}`}
          >
            الجدول
          </button>
        </div>

        <div className="p-6 min-h-[300px]">
          {/* Details Tab */}
          {activeTab === 'details' && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="p-5 bg-gray-50 rounded-xl border border-gray-100">
                  <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                    <BookOpen size={20} className="text-indigo-500"/> معلومات الحلقة
                  </h3>
                  <div className="space-y-3">
                    <div className="flex justify-between py-2 border-b border-gray-200">
                      <span className="text-gray-600">عدد الطلاب</span>
                      <span className="font-semibold">{groupStudents.length}</span>
                    </div>
                    <div className="flex justify-between py-2 border-b border-gray-200">
                      <span className="text-gray-600">الجلسات المجدولة</span>
                      <span className="font-semibold">{groupEvents.length}</span>
                    </div>

                    <div className="py-2 border-b border-gray-200">
                        <div className="flex justify-between items-center mb-1">
                            <span className="text-gray-600">المعلم المسؤول</span>
                            {!isEditingTeacher && (
                                <button 
                                    onClick={() => setIsEditingTeacher(true)} 
                                    className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1"
                                >
                                    <Pencil size={12}/> تغيير
                                </button>
                            )}
                        </div>

                        {isEditingTeacher ? (
                            <div className="flex gap-2 mt-2">
                                <select 
                                    value={selectedTeacherId}
                                    onChange={(e) => setSelectedTeacherId(e.target.value)}
                                    className="flex-1 text-sm border border-gray-300 rounded px-2 py-1 outline-none focus:border-indigo-500"
                                >
                                    <option value="">اختر المعلم...</option>
                                    {teachers.map(t => (
                                        <option key={t.id} value={t.id}>{t.name}</option>
                                    ))}
                                </select>
                                <button 
                                    onClick={handleSaveTeacher}
                                    className="bg-indigo-600 text-white p-1 rounded hover:bg-indigo-700"
                                >
                                    <Check size={16} />
                                </button>
                                <button 
                                    onClick={() => { setIsEditingTeacher(false); setSelectedTeacherId(group.teacherId || ''); }}
                                    className="bg-gray-200 text-gray-600 p-1 rounded hover:bg-gray-300"
                                >
                                    <X size={16} />
                                </button>
                            </div>
                        ) : (
                             groupTeacher ? (
                                <span className="font-semibold text-indigo-600 block">{groupTeacher.name}</span>
                              ) : (
                                <span className="text-red-500 italic text-sm block flex items-center gap-1">
                                    <X size={14}/> معلم مفقود
                                </span>
                              )
                        )}
                    </div>
                  </div>
                </div>

                <div className="p-5 bg-indigo-50 rounded-xl border border-indigo-100">
                  <h3 className="font-bold text-indigo-900 mb-4 flex items-center gap-2">
                    <CheckCircle2 size={20} className="text-indigo-600"/> الحالة
                  </h3>
                  <p className="text-indigo-800 text-sm mb-4">
                    هذه الحلقة نشطة حالياً.
                  </p>
                  <div className="flex gap-2">
                    {groupStudents.length > 0 ? (
                      <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold border border-green-200">نشط</span>
                    ) : (
                      <span className="bg-yellow-100 text-yellow-700 px-3 py-1 rounded-full text-xs font-bold border border-yellow-200">فارغ</span>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Student Tab */}
          {activeTab === 'student' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-800">الطلاب في {group.name}</h3>
                <button 
                  onClick={() => setIsAddingStudent(!isAddingStudent)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition ${isAddingStudent ? 'bg-gray-100 text-gray-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
                >
                  {isAddingStudent ? <X size={16} /> : <Plus size={16} />}
                  {isAddingStudent ? 'إلغاء' : 'إضافة طالب'}
                </button>
              </div>

              {isAddingStudent && (
                <div className="bg-gray-50 p-4 rounded-xl border border-indigo-100 mb-6 animate-[fadeIn_0.2s_ease-out]">
                  <h4 className="font-semibold text-gray-700 mb-3 text-sm">اختر طالباً للإضافة:</h4>
                  {availableStudents.length === 0 ? (
                    <div className="text-gray-500 italic text-sm">جميع الطلاب المتاحين موجودون بالفعل في هذه الحلقة.</div>
                  ) : (
                    <div className="flex flex-col sm:flex-row gap-3">
                      <select
                        value={selectedStudentId}
                        onChange={(e) => setSelectedStudentId(e.target.value)}
                        className="flex-1 p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-sm"
                      >
                        <option value="">-- اختر الطالب --</option>
                        {availableStudents.map(student => (
                          <option key={student.id} value={student.id}>
                            {student.name} (الدرجة: {student.grade}%)
                          </option>
                        ))}
                      </select>
                      <button
                        onClick={handleAddStudent}
                        disabled={!selectedStudentId}
                        className="bg-indigo-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition"
                      >
                        إضافة للحلقة
                      </button>
                    </div>
                  )}
                </div>
              )}

              {groupStudents.length === 0 ? (
                <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                  <Users size={32} className="mx-auto mb-2 opacity-30" />
                  <p>لا يوجد طلاب في هذه الحلقة.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {groupStudents.map(student => (
                    <div key={student.id} className="p-4 border border-gray-200 rounded-lg hover:border-indigo-300 transition bg-white flex items-center gap-3 shadow-sm">
                       <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-bold">
                          {student.name.charAt(0)}
                       </div>
                       <div>
                         <p className="font-semibold text-gray-800">{student.name}</p>
                         <p className="text-xs text-gray-500">الدرجة: {student.grade}%</p>
                       </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Scheduler Tab */}
          {activeTab === 'scheduler' && (
            <div className="space-y-4">
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-800">جدول الحلقة</h3>
              </div>

              {groupEvents.length === 0 ? (
                 <div className="text-center py-10 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                   <Calendar size={32} className="mx-auto mb-2 opacity-30" />
                   <p>لا توجد جلسات مجدولة لهذه الحلقة.</p>
                 </div>
               ) : (
                 <div className="space-y-3">
                   {groupEvents.map(event => {
                     const date = new Date(event.startTime);
                     return (
                      <div key={event.id} className="flex items-start gap-4 p-4 border border-gray-100 rounded-lg bg-gray-50 hover:bg-white hover:shadow-sm transition">
                        <div className="flex-shrink-0 w-16 text-center bg-white rounded border border-gray-200 p-2">
                           <span className="block text-xs font-bold text-gray-500 uppercase">{date.toLocaleDateString('ar-EG', { weekday: 'short' })}</span>
                           <span className="block text-xl font-bold text-gray-800">{date.getDate()}</span>
                        </div>
                        <div>
                          <h4 className="font-bold text-gray-800">{event.title}</h4>
                          <p className="text-sm text-gray-600 flex items-center gap-2 mt-1">
                            <Clock size={14} /> 
                            {date.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })} - 
                            {new Date(date.getTime() + event.durationMinutes * 60000).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}
                          </p>
                          <p className="text-xs text-gray-500 mt-2">{event.description || 'لا يوجد وصف.'}</p>
                        </div>
                        <div className="mr-auto">
                           <span className={`text-xs px-2 py-1 rounded font-medium uppercase ${event.type === 'class' ? 'bg-blue-100 text-blue-700' : event.type === 'meeting' ? 'bg-purple-100 text-purple-700' : 'bg-green-100 text-green-700'}`}>
                             {event.type === 'class' ? 'درس' : event.type === 'meeting' ? 'اجتماع' : 'نشاط'}
                           </span>
                        </div>
                      </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { User, Mail, Lock, Save, Shield, Check, Database, Power, AlertTriangle, Terminal } from 'lucide-react';
import { isLive, saveFirebaseConfig, clearFirebaseConfig } from '../firebase';

interface AdminSettingsProps {
  credentials: { name: string; email: string; password: string };
  onUpdate: (creds: { name: string; email: string; password: string }) => void;
}

export const AdminSettings: React.FC<AdminSettingsProps> = ({ credentials, onUpdate }) => {
  const [formData, setFormData] = useState(credentials);
  const [success, setSuccess] = useState(false);
  const [configInput, setConfigInput] = useState('');
  const [configError, setConfigError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdate(formData);
    setSuccess(true);
    setTimeout(() => setSuccess(false), 3000);
  };

  const handleConnectDb = () => {
    try {
      setConfigError('');
      let jsonStr = configInput;
      if (jsonStr.includes('=')) {
         const match = jsonStr.match(/{[\s\S]*}/);
         if (match) jsonStr = match[0];
      }
      jsonStr = jsonStr.replace(/,(\s*[}\]])/g, '$1');

      let configObj;
      try {
        configObj = JSON.parse(jsonStr);
      } catch (e) {
        throw new Error("تنسيق JSON غير صالح. يرجى التأكد من وضع علامات اقتباس حول المفاتيح.");
      }

      if (!configObj.apiKey || !configObj.projectId) {
        throw new Error("كائن الإعدادات يفتقد حقولاً مطلوبة (apiKey, projectId)");
      }

      saveFirebaseConfig(configObj);
    } catch (e: any) {
      setConfigError(e.message || "فشل في تحليل الإعدادات");
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">إعدادات المسؤول</h2>
        <div className={`px-4 py-1.5 rounded-full text-sm font-semibold flex items-center gap-2 ${isLive ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
            <Database size={16} />
            {isLive ? 'قاعدة البيانات متصلة' : 'وضع غير متصل / تجريبي'}
        </div>
      </div>

      {/* Admin Credentials */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 max-w-3xl">
        <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
           <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-600">
             <Shield size={24} />
           </div>
           <div>
             <h3 className="font-bold text-gray-800 text-lg">بيانات الدخول للمسؤول</h3>
             <p className="text-gray-500 text-sm">تحديث معلومات الوصول الخاصة بك</p>
           </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">الاسم المعروض</label>
                  <div className="relative">
                    <div className="absolute right-0 top-2.5 pr-3 flex items-center pointer-events-none">
                      <User size={18} className="text-gray-400" />
                    </div>
                    <input
                      type="text"
                      required
                      value={formData.name}
                      onChange={e => setFormData({...formData, name: e.target.value})}
                      className="block w-full pr-10 pl-3 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                    />
                  </div>
               </div>

               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">البريد الإلكتروني / اسم المستخدم</label>
                  <div className="relative">
                    <div className="absolute right-0 top-2.5 pr-3 flex items-center pointer-events-none">
                      <Mail size={18} className="text-gray-400" />
                    </div>
                    <input
                      type="email"
                      required
                      value={formData.email}
                      onChange={e => setFormData({...formData, email: e.target.value})}
                      className="block w-full pr-10 pl-3 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                    />
                  </div>
               </div>
           </div>

           <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">كلمة المرور</label>
              <div className="relative">
                <div className="absolute right-0 top-2.5 pr-3 flex items-center pointer-events-none">
                  <Lock size={18} className="text-gray-400" />
                </div>
                <input
                  type="text" 
                  required
                  value={formData.password}
                  onChange={e => setFormData({...formData, password: e.target.value})}
                  className="block w-full pr-10 pl-3 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                />
              </div>
           </div>

           <div className="pt-2 flex items-center gap-4">
              <button
                type="submit"
                className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-indigo-700 transition shadow-sm flex items-center gap-2"
              >
                <Save size={18} />
                حفظ التغييرات
              </button>

              {success && (
                <span className="text-green-600 flex items-center gap-1.5 text-sm font-medium animate-[fadeIn_0.3s_ease-out]">
                  <Check size={18} />
                  تم التحديث بنجاح!
                </span>
              )}
           </div>
        </form>
      </div>

      {/* Database Connection */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 max-w-3xl">
         <div className="flex items-center gap-3 mb-6 pb-6 border-b border-gray-100">
           <div className={`w-12 h-12 rounded-full flex items-center justify-center ${isLive ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'}`}>
             <Database size={24} />
           </div>
           <div>
             <h3 className="font-bold text-gray-800 text-lg">اتصال قاعدة البيانات</h3>
             <p className="text-gray-500 text-sm">الاتصال بـ Firebase Firestore للبيانات الحية</p>
           </div>
        </div>

        {isLive ? (
            <div className="bg-green-50 border border-green-100 rounded-lg p-5 text-center">
                <Check size={40} className="mx-auto text-green-600 mb-3" />
                <h4 className="font-bold text-green-800 text-lg">متصل بنجاح</h4>
                <p className="text-green-700 mb-4">تطبيقك متزامن مع Firebase.</p>
                <button 
                  onClick={clearFirebaseConfig}
                  className="bg-white border border-red-200 text-red-600 px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-50 transition flex items-center gap-2 mx-auto"
                >
                    <Power size={16} /> قطع الاتصال وإعادة الضبط
                </button>
            </div>
        ) : (
            <div className="space-y-4">
                <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg text-sm text-blue-800">
                    <p className="font-semibold flex items-center gap-2 mb-1"><Terminal size={16}/> كيفية الاتصال:</p>
                    <ol className="list-decimal mr-5 space-y-1">
                        <li>اذهب إلى Firebase Console &gt; Project Settings &gt; General</li>
                        <li>انزل إلى "Your apps" واختر Web app</li>
                        <li>انسخ كائن <code>firebaseConfig</code> (JSON)</li>
                        <li>الصقه أدناه واضغط اتصال</li>
                    </ol>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">إعدادات Firebase JSON</label>
                    <textarea 
                        rows={6}
                        value={configInput}
                        onChange={(e) => setConfigInput(e.target.value)}
                        placeholder='{ "apiKey": "...", "authDomain": "...", ... }'
                        className="w-full font-mono text-xs p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        dir="ltr"
                    />
                    {configError && (
                        <p className="text-red-600 text-sm mt-2 flex items-center gap-1"><AlertTriangle size={14} /> {configError}</p>
                    )}
                </div>

                <div className="flex justify-end">
                    <button 
                        onClick={handleConnectDb}
                        disabled={!configInput}
                        className="bg-gray-900 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-black transition shadow-sm flex items-center gap-2 disabled:opacity-50"
                    >
                        <Database size={16} />
                        حفظ واتصال
                    </button>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};
